  onSaveSuccess?: () => void; // Callback cuando se guarda exitosamente
}

export const TradeForm = ({ tradeToEdit, onSaveSuccess }: TradeFormProps = {}) => {
  const queryClient = useQueryClient();
  const [loading, setLoading] = useState(false);

  // Estados para fecha y hora
  const [tradeDate, setTradeDate] = useState<Date | undefined>(new Date());
  const [entryTimeString, setEntryTimeString] = useState<string>('09:00:00');
  const [exitTimeString, setExitTimeString] = useState<string>('10:00:00');

  // Estados para notas y calificación
  const [preTradeNotes, setPreTradeNotes] = useState<string>('');
  const [postTradeNotes, setPostTradeNotes] = useState<string>('');
  const [setupRating, setSetupRating] = useState<string>(''); // Estado para Setup Rating

  // Estados para cuentas
  const [accounts, setAccounts] = useState<any[]>([]);
  const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);
  const [isAccountDialogOpen, setIsAccountDialogOpen] = useState(false);

  // Estado para evaluación de setup compliance
  const [setupCompliance, setSetupCompliance] = useState<'full' | 'partial' | 'none'>('full');
  const [outsidePlanWarning, setOutsidePlanWarning] = useState(false);

  // Trading Plan hook
  const { plan: tradingPlan } = useTradingPlan();

  // Estados unificado para otros campos del formulario
  const [formData, setFormData] = useState({
    par: "",
    pnl_neto: "",
    riesgo: "",
    emocion: "",
    trade_type: "buy" as "buy" | "sell",
  });

  // Estados para URLs de imágenes de gráficos
  const [imageUrlM1, setImageUrlM1] = useState('');
  const [imageUrlM5, setImageUrlM5] = useState('');
  const [imageUrlM15, setImageUrlM15] = useState('');

  // Estados para Trade del Día
  const [isTradeOfDay, setIsTradeOfDay] = useState(false);
  const [tradeOfDayImage, setTradeOfDayImage] = useState('');
  const [tradeOfDayNotes, setTradeOfDayNotes] = useState('');

  // Estado para Tipo de Entrada (multi-select)
  const [selectedEntryTypes, setSelectedEntryTypes] = useState<string[]>([]);

  // --- Handlers ---
  const handleInputChange = (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { id, value } = e.target;
    setFormData((prev) => ({ ...prev, [id]: value }));
  };

  const handleComboboxChange = (id: string, value: string) => {
    setFormData((prev) => ({ ...prev, [id]: value }));
  };

  const handleRadioChange = (value: "buy" | "sell") => {
    setFormData((prev) => ({ ...prev, trade_type: value }));
  };

  // --- Fin Handlers ---

  const fetchAccounts = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await supabase
      .from('accounts')
      .select('id, account_name')
      .eq('user_id', user.id)
      .order('account_name');

    if (error) {
      console.error("Error fetching accounts:", error);
      toast.error("No se pudieron cargar las cuentas");
    } else {
      setAccounts(data || []);

      // Auto-select first account if not editing and no account selected
      if (!tradeToEdit && !selectedAccountId && data && data.length > 0) {
        setSelectedAccountId(data[0].id);
      }
    }
  };

  // Efecto para cargar cuentas
  useEffect(() => {
    fetchAccounts();
  }, []);


  // Efecto para cargar datos del trade a editar
  useEffect(() => {
    // Si estamos en modo EDICIÓN
    if (tradeToEdit) {
      // 1. Rellenar campos de formData
      setFormData({
        par: tradeToEdit.par || '',
        pnl_neto: tradeToEdit.pnl_neto?.toString() || '',
        riesgo: tradeToEdit.riesgo?.toString() || '',
        emocion: tradeToEdit.emocion || '',
        trade_type: tradeToEdit.trade_type || 'buy',
      });

      // 2. Rellenar estados separados (Fechas, Notas, Imágenes, Calificación)
      setTradeDate(tradeToEdit.entry_time ? new Date(tradeToEdit.entry_time) : new Date());
      setEntryTimeString(tradeToEdit.entry_time ? format(new Date(tradeToEdit.entry_time), 'HH:mm:ss') : '09:00:00');
      setExitTimeString(tradeToEdit.exit_time ? format(new Date(tradeToEdit.exit_time), 'HH:mm:ss') : '10:00:00');

      setPreTradeNotes(tradeToEdit.pre_trade_notes || '');
      setPostTradeNotes(tradeToEdit.post_trade_notes || '');
      setSetupRating(tradeToEdit.setup_rating || '');

      setImageUrlM1(tradeToEdit.image_url_m1 || '');
      setImageUrlM5(tradeToEdit.image_url_m5 || '');
      setImageUrlM15(tradeToEdit.image_url_m15 || '');

      // 3. Rellenar Dropdowns
      setSelectedAccountId(tradeToEdit.account_id || null);

      // Setup compliance
      setSetupCompliance(tradeToEdit.setup_compliance || 'full');
      setOutsidePlanWarning(tradeToEdit.is_outside_plan || false);

      // Trade del Día
      setIsTradeOfDay(tradeToEdit.is_trade_of_day || false);
      setTradeOfDayImage(tradeToEdit.trade_of_day_image || '');
      setTradeOfDayNotes(tradeToEdit.trade_of_day_notes || '');

      // Entry Types
      setSelectedEntryTypes(tradeToEdit.entry_types || []);

    } else {
      // Lógica para resetear el formulario si estamos en modo "NUEVO TRADE"
      setFormData({
        par: '',
        pnl_neto: '',
        riesgo: '',
        emocion: '',
        trade_type: 'buy',
      });
      setTradeDate(new Date());
      setEntryTimeString('09:00:00');
      setExitTimeString('10:00:00');
      setPreTradeNotes('');
      setPostTradeNotes('');
      setSetupRating('');
      setImageUrlM1('');
      setImageUrlM5('');
      setImageUrlM15('');
      setSetupCompliance('full');
      setOutsidePlanWarning(false);
      setIsTradeOfDay(false);
      setTradeOfDayImage('');
      setTradeOfDayNotes('');
      setSelectedEntryTypes([]);

      // Auto-seleccionar cuenta si hay cuentas disponibles
      if (accounts.length > 0) {
        setSelectedAccountId(accounts[0].id);
      } else {
        setSelectedAccountId(null);
      }
    }
  }, [tradeToEdit, accounts]);

  // --- handleSubmit Corregido ---
  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuario no autenticado");

      // Validaciones
      if (!selectedAccountId) {
        toast.error("Debes seleccionar una cuenta.");
        setLoading(false);
        return;
      }
      if (!tradeDate || !entryTimeString || !exitTimeString) {
        toast.error("Faltan datos de fecha/hora.");
        setLoading(false);
        return;
      }

      // Combinar Fechas y Horas
      const [entryHours, entryMinutes, entrySeconds] = entryTimeString.split(':').map(Number);
      const entryTimestamp = new Date(tradeDate);
      entryTimestamp.setHours(entryHours, entryMinutes, entrySeconds || 0);

      const [exitHours, exitMinutes, exitSeconds] = exitTimeString.split(':').map(Number);
      const exitTimestamp = new Date(tradeDate);
      exitTimestamp.setHours(exitHours, exitMinutes, exitSeconds || 0);
      if (exitTimestamp < entryTimestamp) {
        exitTimestamp.setDate(exitTimestamp.getDate() + 1);
      }

      // Objeto de datos comunes (lo que se va a guardar)
      const pnlValue = formData.pnl_neto === "" ? 0 : parseFloat(formData.pnl_neto);
      const riesgoValue = parseFloat(formData.riesgo) || null;

      // --- Validación contra Trading Plan ---
      // is_outside_plan is determined solely by the user's setup compliance answer.
      // Automatic plan validations only trigger warnings, they do NOT override the user's answer.
      const isOutsidePlan = setupCompliance !== 'full';

      try {
        const { data: planData } = await (supabase as any)
          .from("trading_plans")
          .select("*")
          .eq("user_id", user.id)
          .maybeSingle();

        if (planData) {
          let planWarning = false;

          // Check max_trades_per_day
          if (planData.max_trades_per_day != null && !tradeToEdit) {
            const todayStr = entryTimestamp.toISOString().split('T')[0];
            const { count } = await supabase
              .from("trades")
              .select("*", { count: "exact", head: true })
              .eq("user_id", user.id)
              .gte("entry_time", todayStr + "T00:00:00")
              .lte("entry_time", todayStr + "T23:59:59");

            if ((count || 0) >= planData.max_trades_per_day) {
              planWarning = true;
            }
          }

          // Check min_rr
          if (planData.min_rr != null && riesgoValue && riesgoValue > 0) {
            const rr = pnlValue / riesgoValue;
            if (rr < planData.min_rr && pnlValue > 0) {
              planWarning = true;
            }
          }

          // Check risk_per_trade (percentage-based)
          if (planData.risk_per_trade != null && riesgoValue && riesgoValue > 0) {
            // Get account initial capital to calculate percentage
            const acct = await supabase
              .from('accounts')
              .select('initial_capital')
              .eq('id', selectedAccountId)
              .single();
            if (acct.data && acct.data.initial_capital > 0) {
              const riskPct = (riesgoValue / acct.data.initial_capital) * 100;
              if (riskPct > planData.risk_per_trade) {
                planWarning = true;
              }
            }
          }

          // Check stop_after_consecutive_losses
          if (planData.stop_after_consecutive_losses != null && !tradeToEdit) {
            const { data: recentTrades } = await supabase
              .from("trades")
              .select("pnl_neto")
              .eq("user_id", user.id)
              .order("entry_time", { ascending: false })
              .limit(planData.stop_after_consecutive_losses);

            if (recentTrades && recentTrades.length >= planData.stop_after_consecutive_losses) {
              const allLosses = recentTrades.every((t: any) => t.pnl_neto < 0);
              if (allLosses) {
                planWarning = true;
              }
            }
          }

          // Show warning if automatic validations detect issues, but do NOT change is_outside_plan
          if (planWarning && setupCompliance === 'full') {
            console.warn("Plan validation warning: Some plan rules were violated, but user confirmed full setup compliance.");
          }
        }
      } catch (planError) {
        console.error("Error validating against trading plan:", planError);
      }

      const tradeDataObject = {
        user_id: user.id,
        account_id: selectedAccountId,
        strategy_id: null,
        par: formData.par.toUpperCase() || null,
        pnl_neto: pnlValue,
        riesgo: riesgoValue,
        trade_type: formData.trade_type,
        emocion: formData.emocion || null,
        setup_rating: setupRating || null,
        entry_time: entryTimestamp.toISOString(),
        exit_time: exitTimestamp.toISOString(),
        pre_trade_notes: preTradeNotes || null,
        post_trade_notes: postTradeNotes || null,
        image_url_m1: imageUrlM1?.trim() || null,
        image_url_m5: imageUrlM5?.trim() || null,
        image_url_m15: imageUrlM15?.trim() || null,
        is_outside_plan: isOutsidePlan,
        setup_compliance: setupCompliance,
        is_trade_of_day: isTradeOfDay,
        trade_of_day_image: isTradeOfDay ? (tradeOfDayImage?.trim() || null) : null,
        trade_of_day_notes: isTradeOfDay ? (tradeOfDayNotes?.trim() || null) : null,
        entry_types: selectedEntryTypes.length > 0 ? selectedEntryTypes : null,
      };

      let tradeId: string | number; // Para guardar el ID del trade

      if (tradeToEdit) {
        // --- MODO EDICIÓN ---
        const { data: updatedTrade, error: updateError } = await supabase
          .from('trades')
          .update(tradeDataObject)
          .eq('id', tradeToEdit.id)
          .select('id') // Pedir el ID de vuelta
          .single();

        if (updateError) throw updateError;
        tradeId = updatedTrade.id;

        // Recalcular capital y highest_balance al editar
        const oldPnl = parseFloat(tradeToEdit.pnl_neto) || 0;
        const newPnl = pnlValue;
        const pnlDelta = newPnl - oldPnl;

        if (pnlDelta !== 0) {
          const { data: accountData, error: accountError } = await supabase
            .from('accounts')
            .select('current_capital, highest_balance, initial_capital')
            .eq('id', selectedAccountId)
            .single();

          if (!accountError && accountData) {
            const currentCap = accountData.current_capital || 0;
            const initialCap = accountData.initial_capital || 0;
            const newCapital = currentCap + pnlDelta;

            const currentHighest = accountData.highest_balance ?? Math.max(currentCap, initialCap);
            const newHighestBalance = Math.max(currentHighest, newCapital);

            await supabase
              .from('accounts')
              .update({
                current_capital: newCapital,
                highest_balance: newHighestBalance
              })
              .eq('id', selectedAccountId);
          }
        }

        toast.success("Trade actualizado con éxito");

      } else {
        // --- MODO CREACIÓN ---
        const { data: newTrade, error: insertError } = await supabase
          .from('trades')
          .insert(tradeDataObject)
          .select('id')
          .single();

        if (insertError) throw insertError;
        if (!newTrade?.id) throw new Error("No se pudo crear el trade.");

        tradeId = newTrade.id;



        // Actualizar Current Capital de la cuenta
        const { data: accountData, error: accountError } = await supabase
          .from('accounts')
          .select('current_capital, highest_balance, initial_capital')
          .eq('id', selectedAccountId)
          .single();

        if (accountError) throw new Error("No se pudo obtener el capital actual de la cuenta.");

        const pnlAmount = parseFloat(formData.pnl_neto);
        const currentCap = accountData?.current_capital || 0;
        const initialCap = accountData?.initial_capital || 0;
        const newCapital = currentCap + pnlAmount;

        // Calculate new highest balance
        // Logic: Highest Balance should NEVER decrease.
        // It starts at Initial Capital.
        // It only goes up if New Capital > Current Highest.

        // 1. Determine the baseline highest (from DB or default to max(current, initial))
        const currentHighest = accountData?.highest_balance ?? Math.max(currentCap, initialCap);

        // 2. Calculate new highest (compare baseline vs new capital)
        // Ensure newHighestBalance exceeds currentHighest to trigger an update, or at least equals it.
        // STRICT HWM RULE: HWM never goes down.
        const newHighestBalance = Math.max(currentHighest, newCapital);

        // Debug info (optional, for development)
        console.log("Trailing Drawdown Debug:", {
          currentCap,
          initialCap,
          pnlAmount,
          newCapital,
          currentHighest,
          newHighestBalance,
          shouldUpdate: newHighestBalance > currentHighest
        });

        const { error: updateError } = await supabase
          .from('accounts')
          .update({
            current_capital: newCapital,
            highest_balance: newHighestBalance
          })
          .eq('id', selectedAccountId);

        if (updateError) throw new Error("Error al actualizar el capital de la cuenta.");

        toast.success("Trade registrado con éxito");
      }

      // Broken rules insertion removed

      // Éxito: Resetear formulario y refrescar datos
      queryClient.invalidateQueries({ queryKey: ["tradesList"] }); // Refresca la tabla
      queryClient.invalidateQueries({ queryKey: ["trades"] }); // Refresca la lista general
      queryClient.invalidateQueries({ queryKey: ["accounts"] }); // Refresca las cuentas (para actualizar capital y highest_balance)

      if (tradeToEdit) {
        queryClient.invalidateQueries({ queryKey: ["trades", tradeId] }); // Refresca el detalle del trade
      }

      if (onSaveSuccess) {
        onSaveSuccess(); // Llama al callback (ej. para cerrar el modal)
      } else {
        // Si es el formulario de "Nueva", resetea los campos
        setFormData({
          par: "",
          pnl_neto: "",
          riesgo: "",
          emocion: "",
          trade_type: "buy",
        });
        setTradeDate(new Date());
        setEntryTimeString('09:00:00');
        setExitTimeString('10:00:00');
        setPreTradeNotes('');
        setPostTradeNotes('');
        setSetupRating('');
        setImageUrlM1('');
        setImageUrlM5('');
        setImageUrlM15('');
        setSetupCompliance('full');
        setOutsidePlanWarning(false);
        setIsTradeOfDay(false);
        setTradeOfDayImage('');
        setTradeOfDayNotes('');
        setSelectedEntryTypes([]);

        // Mantener la cuenta seleccionada o seleccionar la primera
        if (accounts.length > 0) {
          setSelectedAccountId(accounts[0].id);
        } else {
          setSelectedAccountId(null);
        }
      }

    } catch (error: any) {
      toast.error("Error al guardar la operación: " + error.message);
      console.error("Error detallado:", error);
    } finally {
      setLoading(false);
    }
  };
  // --- Fin handleSubmit ---


  // --- JSX del Componente ---
  return (
    <Card className="border-border">
      <CardHeader>
        <CardTitle>{tradeToEdit ? "Editar Operación" : "Registrar Operación"}</CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Selector de Cuenta */}
          <div className="space-y-2">
            <Label htmlFor="account-select">Cuenta *</Label>
            <div className="flex items-center gap-2">
              <Select
                value={selectedAccountId}
                onValueChange={(value) => setSelectedAccountId(value)}
                required
              >
                <SelectTrigger id="account-select" className="flex-grow">
                  <SelectValue placeholder="Seleccionar cuenta..." />
                </SelectTrigger>
                <SelectContent>
                  {accounts.map((account) => (
                    <SelectItem key={account.id} value={account.id}>
                      {account.account_name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Button
                type="button"
                variant="outline"
                size="icon"
                onClick={() => setIsAccountDialogOpen(true)}
                aria-label="Añadir nueva cuenta"
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
          </div>

          {/* Fila Fecha y Horas */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="space-y-2">
              <Label htmlFor="trade-date">Fecha del Trade</Label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant={"outline"} id="trade-date" className="w-full justify-start text-left font-normal">
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {tradeDate ? format(tradeDate, "PPP") : <span>Elige fecha</span>}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0"><Calendar mode="single" selected={tradeDate} onSelect={setTradeDate} initialFocus /></PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <Label htmlFor="entry-time">Hora Entrada</Label>
              <Input id="entry-time" type="time" step="1" value={entryTimeString} onChange={(e) => setEntryTimeString(e.target.value)} required />
            </div>
            <div className="space-y-2">
              <Label htmlFor="exit-time">Hora Salida</Label>
              <Input id="exit-time" type="time" step="1" value={exitTimeString} onChange={(e) => setExitTimeString(e.target.value)} required />
            </div>
          </div>

          {/* Fila Par y PnL Neto */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="par">Par</Label>
              <Combobox
                options={simbolosOptions}
                value={formData.par}
                onChange={(value) => handleComboboxChange('par', value)}
                placeholder="Seleccionar par..."
                emptyMessage="No se encontraron pares."
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="pnl_neto">Resultado final del trade *</Label>
              <Input id="pnl_neto" type="number" step="0.01" placeholder="0.00" value={formData.pnl_neto} onChange={handleInputChange} required className="bg-secondary" />
            </div>
          </div>

          {/* Fila Dirección y Riesgo */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Dirección</Label>
              <RadioGroup value={formData.trade_type} onValueChange={handleRadioChange} className="flex space-x-4 pt-2">
                <div className="flex items-center space-x-2"><RadioGroupItem value="buy" id="buy" /><Label htmlFor="buy">Compra</Label></div>
                <div className="flex items-center space-x-2"><RadioGroupItem value="sell" id="sell" /><Label htmlFor="sell">Venta</Label></div>
              </RadioGroup>
            </div>
            <div className="space-y-2">
              <Label htmlFor="riesgo">Riesgo ($) *</Label>
              <Input id="riesgo" type="number" step="0.01" placeholder="Ej. 100" value={formData.riesgo} onChange={handleInputChange} required />
            </div>
          </div>

          {/* Fila RR Calculado */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="rr-calculated">RR (Calculado)</Label>
              <Input
                id="rr-calculated"
                type="text"
                value={(() => {
                  const risk = parseFloat(formData.riesgo);
                  const pnl = parseFloat(formData.pnl_neto);
                  if (risk > 0 && !isNaN(pnl)) {
                    const ratio = pnl / risk;
                    return `1 : ${ratio.toFixed(2)}`;
                  }
                  return 'N/A';
                })()}
                readOnly
                className="bg-secondary/50 border-dashed text-muted-foreground"
              />
            </div>
            <div className="space-y-2">
              {/* Campo vacío para mantener el layout */}
            </div>
          </div>

          {/* Evaluación del Setup */}
          {tradingPlan && (
            <div className="space-y-3 p-4 border rounded-md bg-muted/10">
              <div className="flex items-center gap-2">
                <Label className="text-base font-semibold">🧠 Evaluación del Setup</Label>
              </div>
              {tradingPlan.setup_rules?.length > 0 && (
                <p className="text-xs text-muted-foreground">
                  Setup principal: <span className="font-medium text-foreground">{tradingPlan.setup_rules[0].name}</span>
                </p>
              )}
              <p className="text-sm text-muted-foreground">¿Este trade cumple tu Setup Principal?</p>
              <RadioGroup
                value={setupCompliance}
                onValueChange={(value) => {
                  setSetupCompliance(value as 'full' | 'partial' | 'none');
                  setOutsidePlanWarning(value !== 'full');
                }}
                className="space-y-2"
              >
                <div className="flex items-center space-x-3 p-2 rounded-md hover:bg-muted/30 transition-colors">
                  <RadioGroupItem value="full" id="setup-full" />
                  <Label htmlFor="setup-full" className="cursor-pointer flex-1">
                    <span className="text-profit font-medium">✔️ Sí, cumple completamente</span>
                  </Label>
                </div>
                <div className="flex items-center space-x-3 p-2 rounded-md hover:bg-muted/30 transition-colors">
                  <RadioGroupItem value="partial" id="setup-partial" />
                  <Label htmlFor="setup-partial" className="cursor-pointer flex-1">
                    <span className="text-yellow-400 font-medium">⚠️ Parcialmente</span>
                  </Label>
                </div>
                <div className="flex items-center space-x-3 p-2 rounded-md hover:bg-muted/30 transition-colors">
                  <RadioGroupItem value="none" id="setup-none" />
                  <Label htmlFor="setup-none" className="cursor-pointer flex-1">
                    <span className="text-loss font-medium">❌ No cumple</span>
                  </Label>
                </div>
              </RadioGroup>

              {outsidePlanWarning && (
                <div className="flex items-center gap-2 p-3 rounded-md bg-yellow-500/10 border border-yellow-500/30 mt-2">
                  <AlertTriangle className="h-4 w-4 text-yellow-500 shrink-0" />
                  <p className="text-sm text-yellow-200">
                    Estás registrando un trade fuera de tu plan de trading.
                  </p>
                </div>
              )}
            </div>
          )}

          {/* Fila Emoción */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="emocion">Emoción</Label>
              <Combobox
                options={emocionOptions}
                value={formData.emocion}
                onChange={(value) => handleComboboxChange('emocion', value)}
                placeholder="Seleccionar emoción..."
                emptyMessage="No se encontraron emociones."
              />
            </div>
            <div className="space-y-2">
              {/* Empty placeholder to keep alignment if needed, or just remove grid */}
            </div>
          </div>


          {/* Calificación del Setup */}
          <div className="space-y-3 pt-4">
            <Label className="font-semibold text-lg">Calificación del Setup</Label>
            <ToggleGroup type="single" value={setupRating} onValueChange={(value) => { if (value) setSetupRating(value); }} className="grid grid-cols-5 gap-3">
              {['Malo', 'Regular', 'Aceptable', 'Bueno', 'Excelente'].map((rating) => (
                <ToggleGroupItem key={rating} value={rating} aria-label={`Calificación ${rating}`}
                  className="h-14 w-full p-2 border border-neutral-700 bg-neutral-900 text-sm md:text-base font-bold text-white data-[state=on]:bg-primary data-[state=on]:border-primary/80 data-[state=on]:text-primary-foreground hover:bg-neutral-800 transition-colors">
                  {rating}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>

          {/* Tipo de Entrada (Multi-select) */}
          <div className="space-y-3 pt-4">
            <Label className="font-semibold text-lg">Tipo de Entrada</Label>
            <p className="text-xs text-muted-foreground">Podés seleccionar más de una opción</p>
            <div className="flex flex-wrap gap-2">
              {ENTRY_TYPE_OPTIONS.map((type) => {
                const isSelected = selectedEntryTypes.includes(type);
                const colorMap: Record<string, { active: string; inactive: string }> = {
                  'IFVG': { active: 'bg-cyan-500 border-cyan-400 text-white', inactive: 'border-cyan-800 text-cyan-400 hover:bg-cyan-900/40' },
                  'OB': { active: 'bg-violet-500 border-violet-400 text-white', inactive: 'border-violet-800 text-violet-400 hover:bg-violet-900/40' },
                  'NR': { active: 'bg-amber-500 border-amber-400 text-white', inactive: 'border-amber-800 text-amber-400 hover:bg-amber-900/40' },
                  'BOS': { active: 'bg-emerald-500 border-emerald-400 text-white', inactive: 'border-emerald-800 text-emerald-400 hover:bg-emerald-900/40' },
                  'Sin setup': { active: 'bg-red-600 border-red-500 text-white', inactive: 'border-red-700 text-red-500 hover:bg-red-900/40' },
                };
                const colors = colorMap[type] || { active: 'bg-primary border-primary/80 text-primary-foreground', inactive: 'border-neutral-700 text-white hover:bg-neutral-800' };
                return (
                  <button
                    key={type}
                    type="button"
                    onClick={() => {
                      setSelectedEntryTypes(prev =>
                        prev.includes(type)
                          ? prev.filter(t => t !== type)
                          : [...prev, type]
                      );
                    }}
                    className={`px-4 py-2 rounded-md border text-sm font-semibold transition-all duration-150 ${
                      isSelected
                        ? `${colors.active} shadow-sm`
                        : `bg-neutral-900 ${colors.inactive}`
                    }`}
                  >
                    {type}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Notas Pre y Post Trade */}
          <div className="space-y-4 pt-4 col-span-1 md:col-span-2"> {/* Ocupa todo el ancho */}
            <Label className="font-semibold text-lg">Análisis (Pre y Post Trade)</Label>
            <div className="space-y-2 p-4 rounded-lg border border-neutral-800 bg-neutral-950/50">
              <Label htmlFor="pre-trade-notes" className="text-primary font-medium">Análisis Pre-Trade</Label>
              <Textarea id="pre-trade-notes" placeholder="¿Por qué estoy tomando este trade? ¿Qué confirmaciones veo?" value={preTradeNotes} onChange={(e) => setPreTradeNotes(e.target.value)} className="bg-transparent border-0 p-0 focus:ring-0 focus-visible:ring-offset-0 focus-visible:ring-0 min-h-[80px]" />
            </div>
            <div className="space-y-2 p-4 rounded-lg border border-neutral-800 bg-neutral-950/50">
              <Label htmlFor="post-trade-notes" className="text-primary font-medium">Reflexión Post-Trade</Label>
              <Textarea id="post-trade-notes" placeholder="¿Qué salió bien/mal? ¿Seguí el plan? ¿Cómo me sentí?" value={postTradeNotes} onChange={(e) => setPostTradeNotes(e.target.value)} className="bg-transparent border-0 p-0 focus:ring-0 focus-visible:ring-offset-0 focus-visible:ring-0 min-h-[80px]" />
            </div>
          </div>

          {/* Sección de Enlaces de Gráficos (M1, M5, M15) */}
          <div className="space-y-2 pt-4 col-span-1 md:col-span-2">
            <Label className="font-semibold text-lg">Enlaces de Gráficos (Opcional)</Label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {/* M1 */}
              <div className="space-y-1">
                <Label htmlFor="image_url_m1" className="text-sm">M1</Label>
                <Input
                  id="image_url_m1"
                  type="url"
                  placeholder="Pegar enlace a la imagen M1..."
                  value={imageUrlM1}
                  onChange={(e) => setImageUrlM1(e.target.value)}
                  className="bg-secondary"
                />
              </div>
              {/* M5 */}
              <div className="space-y-1">
                <Label htmlFor="image_url_m5" className="text-sm">M5</Label>
                <Input
                  id="image_url_m5"
                  type="url"
                  placeholder="Pegar enlace a la imagen M5..."
                  value={imageUrlM5}
                  onChange={(e) => setImageUrlM5(e.target.value)}
                  className="bg-secondary"
                />
              </div>
              {/* M15 */}
              <div className="space-y-1">
                <Label htmlFor="image_url_m15" className="text-sm">M15</Label>
                <Input
                  id="image_url_m15"
                  type="url"
                  placeholder="Pegar enlace a la imagen M15..."
                  value={imageUrlM15}
                  onChange={(e) => setImageUrlM15(e.target.value)}
                  className="bg-secondary"
                />
              </div>
            </div>
          </div>

          {/* Trade del Día */}
          <div className="space-y-3 p-4 border rounded-md bg-muted/10 mt-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Star className={`h-5 w-5 ${isTradeOfDay ? 'text-yellow-400 fill-yellow-400' : 'text-muted-foreground'}`} />
                <Label className="text-base font-semibold cursor-pointer" htmlFor="trade-of-day-switch">Trade del Día</Label>
              </div>
              <Switch
                id="trade-of-day-switch"
                checked={isTradeOfDay}
                onCheckedChange={setIsTradeOfDay}
              />
            </div>
            <p className="text-xs text-muted-foreground">¿Hubo un trade destacado que no tomaste? Guardalo!</p>

            {isTradeOfDay && (
              <div className="space-y-3 mt-2 animate-in fade-in-0 slide-in-from-top-2 duration-200">
                <div className="space-y-1">
                  <Label htmlFor="trade_of_day_image" className="text-sm">Imagen del Trade</Label>
                  <Input
                    id="trade_of_day_image"
                    type="url"
                    placeholder="Pegar enlace a la imagen del trade..."
                    value={tradeOfDayImage}
                    onChange={(e) => setTradeOfDayImage(e.target.value)}
                    className="bg-secondary"
                  />
                </div>
                <div className="space-y-1">
                  <Label htmlFor="trade_of_day_notes" className="text-sm">¿Por qué es tu Trade del Día?</Label>
                  <Textarea
                    id="trade_of_day_notes"
                    placeholder="Explica brevemente por qué destacás esta operación..."
                    value={tradeOfDayNotes}
                    onChange={(e) => setTradeOfDayNotes(e.target.value)}
                    className="bg-transparent border border-neutral-700 min-h-[60px]"
                  />
                </div>
              </div>
            )}
          </div>

          {/* Botón de Enviar */}
          <Button type="submit" className="w-full text-lg py-6 mt-6" disabled={loading}>
            {loading ? "Guardando..." : (tradeToEdit ? "Actualizar Operación" : "Registrar Operación")}
          </Button>
        </form>

        <AccountFormDialog
          isOpen={isAccountDialogOpen}
          onOpenChange={setIsAccountDialogOpen}
          onSaveSuccess={(newAccount) => {
            fetchAccounts();
            if (newAccount?.id) setSelectedAccountId(newAccount.id);
            setIsAccountDialogOpen(false);
          }}
        />


      </CardContent>
    </Card>
  );
};

export default TradeForm;

import { useState, useMemo } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { format } from "date-fns";
import { Search, Trash2, Eye, Pencil, Banknote, Upload } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Link } from "react-router-dom";
import { TradeForm } from "@/components/TradeForm";
import { TradeImporter } from "@/components/trades/TradeImporter";
import { TradeExporter } from "@/components/trades/TradeExporter";

interface TradeRow {
  id: string;
  entry_time: string;
  par: string | null;
  pnl_neto: number | null;
  trade_type: 'buy' | 'sell';
  account_name: string | null;
  rules_compliance_pct: number | null;
}

interface PayoutRow {
  id: string;
  payout_date: string;
  amount: number;
  notes: string | null;
  account_id: string;
}

type UnifiedRow =
  | { type: 'trade'; data: TradeRow; sortDate: Date }
  | { type: 'payout'; data: PayoutRow; sortDate: Date };

export const TradesTable = () => {
  const [symbolFilter, setSymbolFilter] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [editingTrade, setEditingTrade] = useState<any | null>(null);
  const [isImporterOpen, setIsImporterOpen] = useState(false);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: trades = [], isLoading } = useQuery({
    queryKey: ["trades"],
    queryFn: async (): Promise<TradeRow[]> => {
      const { data, error } = await (supabase as any).rpc('get_trades_list');
      if (error) throw error;
      return (data ?? []) as TradeRow[];
    },
  });

  const { data: payouts = [], isLoading: isLoadingPayouts } = useQuery({
    queryKey: ["payouts-list"],
    queryFn: async (): Promise<PayoutRow[]> => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return [];

      const { data, error } = await supabase
        .from('payouts')
        .select('id, payout_date, amount, notes, account_id')
        .eq('user_id', user.id)
        .order('payout_date', { ascending: false });

      if (error) throw error;
      return (data ?? []) as PayoutRow[];
    },
  });

  const handleDelete = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (window.confirm('¿Estás seguro de que quieres borrar esta operación?')) {
      try {
        const { error } = await supabase
          .from('trades')
          .delete()
          .eq('id', id);

        if (error) {
          console.error("Error al borrar el trade:", error);
          toast({
            title: "Error",
            description: "No se pudo borrar la operación: " + error.message,
            variant: "destructive",
          });
        } else {
          toast({
            title: "Éxito",
            description: "Operación borrada correctamente",
          });
          queryClient.invalidateQueries({ queryKey: ["trades"] });
        }
      } catch (error) {
        console.error("Error inesperado:", error);
        toast({
          title: "Error",
          description: "Ocurrió un error inesperado al borrar la operación",
          variant: "destructive",
        });
      }
    }
  };

  const handleDeletePayout = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (window.confirm('¿Estás seguro de que quieres borrar este retiro?')) {
      try {
        // Get payout details before deleting to restore balance
        const { data: payout } = await supabase
          .from('payouts')
          .select('amount, account_id')
          .eq('id', id)
          .single();

        const { error } = await supabase
          .from('payouts')
          .delete()
          .eq('id', id);

        if (error) {
          toast({
            title: "Error",
            description: "No se pudo borrar el retiro: " + error.message,
            variant: "destructive",
          });
        } else {
          // Restore balance
          if (payout) {
            const { data: account } = await supabase
              .from('accounts')
              .select('current_capital')
              .eq('id', payout.account_id)
              .single();

            if (account) {
              await supabase
                .from('accounts')
                .update({ current_capital: account.current_capital + payout.amount })
                .eq('id', payout.account_id);
            }
          }

          toast({
            title: "Éxito",
            description: "Retiro borrado correctamente",
          });
          queryClient.invalidateQueries({ queryKey: ["payouts-list"] });
          queryClient.invalidateQueries({ queryKey: ["payouts"] });
          queryClient.invalidateQueries({ queryKey: ["accounts"] });
        }
      } catch (error) {
        console.error("Error inesperado:", error);
        toast({
          title: "Error",
          description: "Ocurrió un error inesperado al borrar el retiro",
          variant: "destructive",
        });
      }
    }
  };

  const handleEdit = async (tradeId: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    try {
      // Cargar el trade completo desde la base de datos
      const { data, error } = await supabase
        .from('trades')
        .select('*')
        .eq('id', tradeId)
        .single();

      if (error) throw error;
      if (data) {
        setEditingTrade(data);
      }
    } catch (error: any) {
      console.error("Error al cargar el trade:", error);
      toast({
        title: "Error",
        description: "No se pudo cargar la operación para editar: " + error.message,
        variant: "destructive",
      });
    }
  };

  // Merge trades and payouts into a unified list sorted by date desc
  const unifiedRows: UnifiedRow[] = useMemo(() => {
    const tradeRows: UnifiedRow[] = trades
      .filter((trade) => {
        const par = (trade.par ?? '').toLowerCase();
        const matchesSymbol = symbolFilter ? par.includes(symbolFilter.toLowerCase()) : true;
        const tradeDate = trade.entry_time ? new Date(trade.entry_time) : undefined;
        const matchesStartDate = startDate && tradeDate ? tradeDate >= new Date(startDate) : true;
        const matchesEndDate = endDate && tradeDate ? tradeDate <= new Date(endDate) : true;
        return matchesSymbol && matchesStartDate && matchesEndDate;
      })
      .map(t => ({
        type: 'trade' as const,
        data: t,
        sortDate: new Date(t.entry_time),
      }));

    const payoutRows: UnifiedRow[] = payouts
      .filter((p) => {
        const payoutDate = new Date(p.payout_date);
        const matchesStartDate = startDate ? payoutDate >= new Date(startDate) : true;
        const matchesEndDate = endDate ? payoutDate <= new Date(endDate) : true;
        // don't filter by symbol for payouts
        return matchesStartDate && matchesEndDate;
      })
      .map(p => ({
        type: 'payout' as const,
        data: p,
        sortDate: new Date(p.payout_date),
      }));

    return [...tradeRows, ...payoutRows].sort((a, b) => b.sortDate.getTime() - a.sortDate.getTime());
  }, [trades, payouts, symbolFilter, startDate, endDate]);

  const loading = isLoading || isLoadingPayouts;

  return (
    <>
      <Card className="border-border">
        <CardHeader>
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <CardTitle>Mis Trades</CardTitle>
            <div className="flex items-center gap-2">
               <Button variant="outline" onClick={() => setIsImporterOpen(true)}>
                 <Upload className="mr-2 h-4 w-4" /> Importar CSV
               </Button>
               <TradeExporter />
            </div>
          </div>
          <div className="grid gap-4 md:grid-cols-3 pt-4">
            <div className="space-y-2">
              <Label htmlFor="symbol-filter">Filtrar por Par</Label>
              <div className="relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  id="symbol-filter"
                  placeholder="EURUSD, NAS100..."
                  value={symbolFilter}
                  onChange={(e) => setSymbolFilter(e.target.value)}
                  className="pl-9"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="start-date">Fecha Inicio</Label>
              <Input
                id="start-date"
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="end-date">Fecha Fin</Label>
              <Input
                id="end-date"
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="text-center py-8 text-muted-foreground">Cargando...</div>
          ) : unifiedRows.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              No se encontraron operaciones
            </div>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Fecha</TableHead>
                    <TableHead>Par</TableHead>
                    <TableHead className="text-right">PnL</TableHead>
                    <TableHead>Dirección</TableHead>
                    <TableHead>Cuenta</TableHead>
                    <TableHead>% Reglas</TableHead>
                    <TableHead className="text-center">Acciones</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {unifiedRows.map((row) => {
                    if (row.type === 'payout') {
                      const p = row.data;
                      return (
                        <TableRow key={`payout-${p.id}`} className="hover:bg-violet-500/5 border-l-2 border-l-violet-500">
                          <TableCell className="font-medium">
                            {format(new Date(p.payout_date), "dd/MM/yyyy HH:mm")}
                          </TableCell>
                          <TableCell>
                            <Badge variant="outline" className="border-violet-500/50 text-violet-400 gap-1">
                              <Banknote className="h-3 w-3" />
                              RETIRO
                            </Badge>
                          </TableCell>
                          <TableCell className="text-right font-medium text-violet-400">
                            -${Number(p.amount).toFixed(2)}
                          </TableCell>
                          <TableCell className="text-violet-400">
                            💸 Payout
                          </TableCell>
                          <TableCell className="text-muted-foreground text-xs">
                            {p.notes || '-'}
                          </TableCell>
                          <TableCell>-</TableCell>
                          <TableCell className="text-center">
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={(e) => handleDeletePayout(p.id, e)}
                              className="text-destructive hover:text-destructive hover:bg-destructive/10"
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      );
                    }

                    const trade = row.data;
                    const pnl = Number(trade.pnl_neto ?? 0);
                    const isBuy = trade.trade_type === 'buy';
                    return (
                      <TableRow key={trade.id} className="hover:bg-muted/50">
                        <TableCell className="font-medium">
                          {trade.entry_time ? format(new Date(trade.entry_time), "dd/MM/yyyy HH:mm") : '-'}
                        </TableCell>
                        <TableCell>
                          <Badge variant="outline">{trade.par ?? '-'}</Badge>
                        </TableCell>
                        <TableCell className={`text-right font-medium ${pnl >= 0 ? 'text-profit-custom' : 'text-loss-custom'}`}>
                          ${pnl.toFixed(2)}
                        </TableCell>
                        <TableCell className={isBuy ? 'text-green-600' : 'text-red-600'}>
                          {isBuy ? 'Compra' : 'Venta'}
                        </TableCell>
                        <TableCell>{trade.account_name ?? '-'}</TableCell>
                        <TableCell>
                          {typeof trade.rules_compliance_pct === 'number' ? `${Math.round(trade.rules_compliance_pct)}%` : '-'}
                        </TableCell>
                        <TableCell className="text-center space-x-1">
                          <Button variant="ghost" size="icon" asChild>
                            <Link to={`/trade/${trade.id}`}>
                              <Eye className="h-4 w-4" />
                            </Link>
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={(e) => handleEdit(trade.id, e)}
                            className="hover:bg-accent"
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={(e) => handleDelete(trade.id, e)}
                            className="text-destructive hover:text-destructive hover:bg-destructive/10"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Dialog de Edición */}
      <Dialog open={!!editingTrade} onOpenChange={(open) => !open && setEditingTrade(null)}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <TradeForm
            tradeToEdit={editingTrade}
            onSaveSuccess={() => {
              setEditingTrade(null);
              queryClient.invalidateQueries({ queryKey: ["trades"] });
            }}
          />
        </DialogContent>
      </Dialog>
      
      <TradeImporter 
        isOpen={isImporterOpen} 
        onOpenChange={setIsImporterOpen} 
        onSuccess={() => {
          queryClient.invalidateQueries({ queryKey: ["trades"] });
          queryClient.invalidateQueries({ queryKey: ["dashboard-metrics"] });
        }} 
      />
    </>
  );
};

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";

export const WelcomeMessage = () => {
  const [userName, setUserName] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [welcomeMessage, setWelcomeMessage] = useState("");
  const [tempName, setTempName] = useState(""); // Para el input del formulario
  const { toast } = useToast();

  const messages = [
    "¿listo para guardar tus trades?",
    "¿qué tal va ese análisis?",
    "¡a por esos pips!",
    "la disciplina es la clave.",
    "¡que tengas un gran día de trading!"
  ];

  useEffect(() => {
    const fetchUserData = async () => {
      try {
        const { data, error } = await supabase.auth.getUser();

        if (error) {
          throw error;
        }

        if (data.user && data.user.user_metadata.first_name) {
          setUserName(data.user.user_metadata.first_name);
          // Elige un mensaje aleatorio
          const randomMsg = messages[Math.floor(Math.random() * messages.length)];
          setWelcomeMessage(randomMsg);
        } else {
          setUserName(null);
        }
      } catch (error) {
        console.error("Error al obtener datos del usuario:", error);
        toast({
          title: "Error",
          description: "No se pudieron cargar los datos del usuario",
          variant: "destructive",
        });
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
  }, []);

  const handleSaveName = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!tempName.trim()) return;

    try {
      setIsLoading(true);

      const { data, error } = await supabase.auth.updateUser({
        data: { first_name: tempName } // Así se guarda en user_metadata
      });

      if (error) {
        throw error;
      } else if (data.user) {
        setUserName(data.user.user_metadata.first_name);
        // Elige un mensaje aleatorio
        const randomMsg = messages[Math.floor(Math.random() * messages.length)];
        setWelcomeMessage(randomMsg);

        toast({
          title: "¡Nombre guardado!",
          description: "Tu nombre se ha guardado correctamente",
        });
      }
    } catch (error) {
      console.error("Error al guardar el nombre:", error);
      toast({
        title: "Error",
        description: "No se pudo guardar tu nombre",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="mb-6  rounded-lg">
      {isLoading ? (
        <p className="text-center py-2">Cargando...</p>
      ) : userName ? (
        <h2 className="welcome-title">
          Hola de nuevo, <span className="highlighted-name">{userName}</span>. {welcomeMessage}
        </h2>
      ) : (
        <form onSubmit={handleSaveName} className="space-y-4">
          <h3 className="text-xl font-medium">¡Bienvenido! ¿Cómo te llamas?</h3>
          <Input
            type="text"
            value={tempName}
            onChange={(e) => setTempName(e.target.value)}
            placeholder="Escribe tu nombre..."
            className="max-w-md"
          />
          <Button type="submit">Guardar</Button>
        </form>
      )}
    </div>
  );
};

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { Eye, ArrowLeft, TrendingUp, TrendingDown, Minus, Clock, Target, Star, AlertTriangle, CheckCircle, Ban, XCircle, ImageIcon } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { Label } from "@/components/ui/label";

interface DayTradesModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  date: Date | null;
  accountTradeIds: string[]; // IDs of trades on that day for the selected account
}

interface TradeFull {
  id: string;
  par: string | null;
  pnl_neto: number;
  riesgo: number | null;
  trade_type: "buy" | "sell";
  setup_rating: string | null;
  entry_time: string;
  exit_time: string | null;
  pre_trade_notes: string | null;
  post_trade_notes: string | null;
  is_outside_plan: boolean;
  setup_compliance: 'full' | 'partial' | 'none' | null;
  entry_types: string[] | null;
  emocion: string | null;
  image_url_m1?: string | null;
  image_url_m5?: string | null;
  image_url_m15?: string | null;
  is_trade_of_day?: boolean;
  trade_of_day_image?: string | null;
  trade_of_day_notes?: string | null;
  accounts?: {
    account_name: string;
  };
}

export const DayTradesModal = ({ open, onOpenChange, date, accountTradeIds }: DayTradesModalProps) => {
  const [trades, setTrades] = useState<TradeFull[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedTrade, setSelectedTrade] = useState<TradeFull | null>(null);
  const [selectedImageUrl, setSelectedImageUrl] = useState<string | null>(null);

  useEffect(() => {
    if (!open || !date || accountTradeIds.length === 0) {
      setTrades([]);
      setSelectedTrade(null);
      return;
    }

    const fetchTrades = async () => {
      setLoading(true);
      try {
        const { data, error } = await supabase
          .from("trades")
          .select("*, accounts(account_name)")
          .in("id", accountTradeIds)
          .order("entry_time", { ascending: true });

        if (error) throw error;
        setTrades((data as any[]) || []);
      } catch (e) {
        console.error("Error fetching day trades:", e);
      } finally {
        setLoading(false);
      }
    };

    fetchTrades();
  }, [open, date, accountTradeIds]);

  const handleClose = (isOpen: boolean) => {
    if (!isOpen) {
      setSelectedTrade(null);
    }
    onOpenChange(isOpen);
  };

  const totalPnL = trades.reduce((sum, t) => sum + Number(t.pnl_neto), 0);

  // Entry type badge colors
  const entryTypeColors: Record<string, string> = {
    'IFVG': 'bg-cyan-500/15 border-cyan-500/40 text-cyan-400',
    'OB': 'bg-violet-500/15 border-violet-500/40 text-violet-400',
    'NR': 'bg-amber-500/15 border-amber-500/40 text-amber-400',
    'BOS': 'bg-emerald-500/15 border-emerald-500/40 text-emerald-400',
    'Sin setup': 'bg-red-600/20 border-red-500/50 text-red-500',
  };

  // ─── Trade Detail View ───
  if (selectedTrade) {
    const trade = selectedTrade;
    const isPnlPositive = trade.pnl_neto > 0;
    const isPnlNegative = trade.pnl_neto < 0;

    return (
      <Dialog open={open} onOpenChange={handleClose}>
        <DialogContent className="sm:max-w-[620px] max-h-[85vh] overflow-y-auto">
          <DialogHeader>
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedTrade(null)}
                className="gap-1 text-muted-foreground hover:text-foreground -ml-2"
              >
                <ArrowLeft className="h-4 w-4" />
                Volver
              </Button>
            </div>
            <DialogTitle className="flex items-center justify-between mt-2">
              <div className="flex items-center gap-2">
                <span className="text-lg font-bold">{trade.par || "Sin par"}</span>
                <Badge variant="outline" className={`text-xs ${trade.trade_type === 'buy' ? 'border-emerald-500/50 text-emerald-400' : 'border-red-500/50 text-red-400'}`}>
                  {trade.trade_type === 'buy' ? '▲ Buy' : '▼ Sell'}
                </Badge>
              </div>
              <span className={`text-xl font-bold ${isPnlPositive ? 'text-emerald-400' : isPnlNegative ? 'text-red-400' : 'text-neutral-400'}`}>
                {isPnlPositive ? '+' : ''}{trade.pnl_neto.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}
              </span>
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 mt-2">
            {/* Summary Grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Cuenta</p>
                <p className="text-sm font-semibold">{trade.accounts?.account_name || "—"}</p>
              </div>
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Riesgo</p>
                <p className="text-sm font-semibold">{trade.riesgo != null ? `$${trade.riesgo.toLocaleString()}` : "—"}</p>
              </div>
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Entrada</p>
                <p className="text-sm font-semibold">{trade.entry_time ? format(new Date(trade.entry_time), "HH:mm", { locale: es }) : "—"}</p>
              </div>
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Salida</p>
                <p className="text-sm font-semibold">{trade.exit_time ? format(new Date(trade.exit_time), "HH:mm", { locale: es }) : "—"}</p>
              </div>
            </div>

            {/* Calificación del Setup */}
            {trade.setup_rating && (
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Calificación del Setup</p>
                <div className="flex items-center gap-1.5">
                  <Star className="h-4 w-4 text-amber-400" />
                  <span className="text-sm font-semibold">{trade.setup_rating}</span>
                </div>
              </div>
            )}

            {/* Entry Types */}
            {trade.entry_types && trade.entry_types.length > 0 && (
              <div>
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-2">Tipo de Entrada</p>
                <div className="flex flex-wrap gap-1.5">
                  {trade.entry_types.map((type) => (
                    <Badge key={type} variant="outline" className={`px-2.5 py-0.5 text-xs font-semibold ${entryTypeColors[type] || 'bg-primary/10 border-primary/30 text-primary'}`}>
                      {type}
                    </Badge>
                  ))}
                </div>
              </div>
            )}

            {/* Emotion */}
            {trade.emocion && (
              <div className="bg-neutral-800/60 rounded-lg p-3">
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Emoción</p>
                <p className="text-sm font-semibold">{trade.emocion}</p>
              </div>
            )}

            {/* Plan Evaluation */}
            <div className={`rounded-lg p-3 border ${!trade.is_outside_plan ? 'bg-emerald-500/5 border-emerald-500/20' : 'bg-red-500/5 border-red-500/20'}`}>
              <div className="flex items-center gap-2">
                {!trade.is_outside_plan ? (
                  <CheckCircle className="h-4 w-4 text-emerald-400" />
                ) : (
                  <AlertTriangle className="h-4 w-4 text-red-400" />
                )}
                <span className="text-sm font-medium">
                  {!trade.is_outside_plan ? 'Dentro del plan' : 'Fuera del plan'}
                </span>
              </div>
              {trade.setup_compliance && (
                <div className="flex items-center gap-1.5 mt-2 ml-6">
                  {trade.setup_compliance === 'full' && <CheckCircle className="h-3.5 w-3.5 text-emerald-400" />}
                  {trade.setup_compliance === 'partial' && <AlertTriangle className="h-3.5 w-3.5 text-amber-400" />}
                  {trade.setup_compliance === 'none' && <XCircle className="h-3.5 w-3.5 text-red-400" />}
                  <span className="text-xs text-muted-foreground">
                    Setup: {trade.setup_compliance === 'full' ? 'Completo' : trade.setup_compliance === 'partial' ? 'Parcial' : 'No cumplido'}
                  </span>
                </div>
              )}
            </div>

            {/* Notes */}
            {(trade.pre_trade_notes || trade.post_trade_notes) && (
              <div className="space-y-3">
                {trade.pre_trade_notes && (
                  <div className="bg-neutral-800/60 rounded-lg p-3">
                    <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Análisis Pre-Trade</p>
                    <p className="text-sm text-foreground/80 whitespace-pre-wrap">{trade.pre_trade_notes}</p>
                  </div>
                )}
                {trade.post_trade_notes && (
                  <div className="bg-neutral-800/60 rounded-lg p-3">
                    <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-1">Análisis Post-Trade</p>
                    <p className="text-sm text-foreground/80 whitespace-pre-wrap">{trade.post_trade_notes}</p>
                  </div>
                )}
              </div>
            )}

            {/* Trade Images (M1, M5, M15) */}
            {((trade as any).image_url_m1 || (trade as any).image_url_m5 || (trade as any).image_url_m15) && (
              <div>
                <p className="text-[11px] text-muted-foreground uppercase tracking-wider mb-2 flex items-center gap-1">
                  <ImageIcon className="h-3 w-3" />
                  Imágenes del Trade
                </p>
                <div className="grid grid-cols-3 gap-2">
                  {(trade as any).image_url_m1 && (
                    <button
                      onClick={() => setSelectedImageUrl((trade as any).image_url_m1)}
                      className="relative rounded-md overflow-hidden border border-border hover:opacity-80 transition-opacity aspect-video bg-neutral-900"
                    >
                      <img src={(trade as any).image_url_m1} alt="M1" className="w-full h-full object-cover" />
                      <span className="absolute bottom-0.5 left-1 text-[9px] font-bold bg-black/70 px-1.5 py-0.5 rounded text-white">M1</span>
                    </button>
                  )}
                  {(trade as any).image_url_m5 && (
                    <button
                      onClick={() => setSelectedImageUrl((trade as any).image_url_m5)}
                      className="relative rounded-md overflow-hidden border border-border hover:opacity-80 transition-opacity aspect-video bg-neutral-900"
                    >
                      <img src={(trade as any).image_url_m5} alt="M5" className="w-full h-full object-cover" />
                      <span className="absolute bottom-0.5 left-1 text-[9px] font-bold bg-black/70 px-1.5 py-0.5 rounded text-white">M5</span>
                    </button>
                  )}
                  {(trade as any).image_url_m15 && (
                    <button
                      onClick={() => setSelectedImageUrl((trade as any).image_url_m15)}
                      className="relative rounded-md overflow-hidden border border-border hover:opacity-80 transition-opacity aspect-video bg-neutral-900"
                    >
                      <img src={(trade as any).image_url_m15} alt="M15" className="w-full h-full object-cover" />
                      <span className="absolute bottom-0.5 left-1 text-[9px] font-bold bg-black/70 px-1.5 py-0.5 rounded text-white">M15</span>
                    </button>
                  )}
                </div>
              </div>
            )}

            {/* Trade del Día */}
            {(trade as any).is_trade_of_day && (
              <div className="rounded-lg p-3 border border-yellow-500/40 bg-yellow-500/5">
                <div className="flex items-center gap-2 mb-2">
                  <Star className="h-4 w-4 text-yellow-400 fill-yellow-400" />
                  <span className="text-sm font-semibold text-yellow-300">Trade del Día</span>
                </div>
                {(trade as any).trade_of_day_image && (
                  <button
                    onClick={() => setSelectedImageUrl((trade as any).trade_of_day_image)}
                    className="block w-full max-w-md h-40 rounded-md overflow-hidden border border-yellow-500/30 hover:opacity-80 transition-opacity bg-neutral-900 mb-2"
                  >
                    <img src={(trade as any).trade_of_day_image} alt="Trade del Día" className="w-full h-full object-cover" />
                  </button>
                )}
                {(trade as any).trade_of_day_notes && (
                  <p className="text-xs text-neutral-200 whitespace-pre-wrap">{(trade as any).trade_of_day_notes}</p>
                )}
              </div>
            )}
          </div>

          {/* Image Lightbox */}
          {selectedImageUrl && (
            <Dialog open={!!selectedImageUrl} onOpenChange={() => setSelectedImageUrl(null)}>
              <DialogContent className="max-w-5xl h-[90vh] bg-transparent border-0 shadow-none flex items-center justify-center p-0">
                <img
                  src={selectedImageUrl}
                  alt="Vista detallada"
                  className="max-w-full max-h-full object-contain"
                />
              </DialogContent>
            </Dialog>
          )}
        </DialogContent>
      </Dialog>
    );
  }

  // ─── Trade List View ───
  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-[620px] max-h-[85vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center justify-between">
            <span>
              {date ? format(date, "EEEE d 'de' MMMM, yyyy", { locale: es }) : ""}
            </span>
            <span className={`text-lg font-bold ${totalPnL > 0 ? 'text-emerald-400' : totalPnL < 0 ? 'text-red-400' : 'text-neutral-400'}`}>
              {totalPnL > 0 ? '+' : ''}{totalPnL.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}
            </span>
          </DialogTitle>
          <p className="text-xs text-muted-foreground">
            {trades.length} {trades.length === 1 ? 'operación' : 'operaciones'} en este día
          </p>
        </DialogHeader>

        <div className="mt-2 space-y-2">
          {loading ? (
            Array.from({ length: 3 }).map((_, i) => (
              <Skeleton key={i} className="h-16 w-full rounded-lg" />
            ))
          ) : trades.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <p className="text-sm">No hay trades registrados este día</p>
            </div>
          ) : (
            trades.map((trade) => {
              const isPnlPositive = trade.pnl_neto > 0;
              const isPnlNegative = trade.pnl_neto < 0;
              return (
                <div
                  key={trade.id}
                  className={`flex items-center justify-between p-3 rounded-lg border transition-colors hover:bg-muted/30 ${
                    isPnlPositive
                      ? 'border-emerald-500/20 bg-emerald-500/5'
                      : isPnlNegative
                        ? 'border-red-500/20 bg-red-500/5'
                        : 'border-border bg-muted/10'
                  }`}
                >
                  {/* Left: icon + info */}
                  <div className="flex items-center gap-3 min-w-0">
                    <div className={`flex items-center justify-center w-9 h-9 rounded-full shrink-0 ${
                      isPnlPositive ? 'bg-emerald-500/15' : isPnlNegative ? 'bg-red-500/15' : 'bg-neutral-700'
                    }`}>
                      {isPnlPositive ? <TrendingUp className="h-4 w-4 text-emerald-400" /> 
                        : isPnlNegative ? <TrendingDown className="h-4 w-4 text-red-400" /> 
                        : <Minus className="h-4 w-4 text-neutral-400" />}
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-sm font-semibold truncate">{trade.par || "—"}</span>
                        <Badge variant="outline" className={`text-[10px] px-1.5 py-0 ${trade.trade_type === 'buy' ? 'border-emerald-500/30 text-emerald-400' : 'border-red-500/30 text-red-400'}`}>
                          {trade.trade_type === 'buy' ? 'Buy' : 'Sell'}
                        </Badge>
                      </div>
                      <div className="flex items-center gap-2 text-[11px] text-muted-foreground mt-0.5">
                        <span className="flex items-center gap-0.5">
                          <Clock className="h-3 w-3" />
                          {trade.entry_time ? format(new Date(trade.entry_time), "HH:mm") : "—"}
                        </span>
                        <span>•</span>
                        <span className="truncate">{trade.accounts?.account_name || "—"}</span>
                      </div>
                    </div>
                  </div>

                  {/* Right: PnL + eye */}
                  <div className="flex items-center gap-3 shrink-0">
                    <span className={`text-sm font-bold ${
                      isPnlPositive ? 'text-emerald-400' : isPnlNegative ? 'text-red-400' : 'text-neutral-400'
                    }`}>
                      {isPnlPositive ? '+' : ''}${Math.abs(trade.pnl_neto).toFixed(2)}
                    </span>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8 text-muted-foreground hover:text-foreground"
                      onClick={() => setSelectedTrade(trade)}
                    >
                      <Eye className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { AlertTriangle, TrendingDown, ShieldCheck, ShieldAlert, Ban, Trophy, DollarSign, Ruler, Target, PartyPopper } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useQueryClient } from "@tanstack/react-query";

interface Account {
  id: string;
  account_name: string;
  account_type: 'personal' | 'evaluation' | 'live';
  initial_capital: number;
  current_capital: number;
  drawdown_type?: 'fixed' | 'trailing' | null;
  drawdown_amount?: number | null;
  highest_balance?: number | null;
  profit_target?: number | null;
  evaluation_passed?: boolean;
}

interface RiskAccountCardProps {
  account: Account;
  currentBalance: number;
  highWaterMark?: number;
  profitTarget?: number;
}

export const RiskAccountCard = ({ account, currentBalance, highWaterMark: hwmProp, profitTarget }: RiskAccountCardProps) => {
  const [showPassDialog, setShowPassDialog] = useState(false);
  const [wantsConsistency, setWantsConsistency] = useState(false);
  const [minProfitDays, setMinProfitDays] = useState(5);
  const [withdrawalPct, setWithdrawalPct] = useState(50);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const queryClient = useQueryClient();

  if (!account.drawdown_amount || account.drawdown_amount <= 0) {
    return null;
  }

  const drawdownAmount = account.drawdown_amount;
  const drawdownType = account.drawdown_type || 'trailing';

  // ── Calculate Logic ──────────────────────────────────────────
  let lossLimit = 0;
  let highWaterMark = account.initial_capital;

  if (drawdownType === 'fixed') {
    lossLimit = account.initial_capital - drawdownAmount;
  } else {
    highWaterMark = hwmProp ?? account.initial_capital;
    const trailingLimit = highWaterMark - drawdownAmount;
    lossLimit = Math.min(trailingLimit, account.initial_capital);
  }

  const distanceToLimit = currentBalance - lossLimit;
  const isBreached = distanceToLimit < 0;

  // ── Alert Zones ──────────────────────────────────────────────
  const criticalThreshold = drawdownAmount * 0.25;

  let status: 'safe' | 'warning' | 'breached' = 'safe';
  if (isBreached) status = 'breached';
  else if (distanceToLimit <= criticalThreshold) status = 'warning';

  const usedDrawdown = drawdownAmount - distanceToLimit;
  const progressPct = Math.max(0, Math.min(100, ((drawdownAmount - Math.max(0, usedDrawdown)) / drawdownAmount) * 100));

  // ── Styles ────────────────────────────────────────────────────
  let cardBorderColor = "border-l-4 border-l-emerald-500";
  let badgeClasses = "bg-emerald-500/10 text-emerald-500 border-emerald-500/30";
  let badgeIcon = <ShieldCheck className="w-3 h-3" />;
  let badgeText = "Operativo";
  let distanceTextColor = "text-emerald-400";
  let progressBarColor = "bg-emerald-500";

  if (status === 'warning') {
    cardBorderColor = "border-l-4 border-l-amber-500";
    badgeClasses = "bg-amber-500/10 text-amber-500 border-amber-500/30 animate-pulse";
    badgeIcon = <ShieldAlert className="w-3 h-3" />;
    badgeText = "Zona de Riesgo";
    distanceTextColor = "text-amber-400";
    progressBarColor = "bg-amber-500";
  } else if (status === 'breached') {
    cardBorderColor = "border-l-4 border-l-red-600 shadow-md shadow-red-900/20";
    badgeClasses = "bg-red-500/10 text-red-500 border-red-500/30";
    badgeIcon = <Ban className="w-3 h-3" />;
    badgeText = "Cuenta Perdida";
    distanceTextColor = "text-red-400";
    progressBarColor = "bg-red-500";
  }

  const formatCurrency = (val: number) =>
    new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(val);

  // ── Profit Target Achievement ────────────────────────────────
  const profitAchievement = useMemo(() => {
    if (!profitTarget || profitTarget <= 0) return null;
    const profitSoFar = currentBalance - account.initial_capital;
    const remaining = profitTarget - profitSoFar;
    const progressPctTarget = Math.max(0, Math.min(100, (profitSoFar / profitTarget) * 100));
    const remainingPct = ((remaining / account.initial_capital) * 100);
    const isAchieved = remaining <= 0;
    const targetBalance = account.initial_capital + profitTarget;
    return { profitSoFar, remaining, progressPctTarget, remainingPct, isAchieved, targetBalance };
  }, [profitTarget, currentBalance, account.initial_capital]);

  const isEvaluation = account.account_type === 'evaluation';
  const showCongrats = isEvaluation && profitAchievement?.isAchieved && !account.evaluation_passed;

  // ── Handle Account Pass ──────────────────────────────────────
  const handleAccountPass = async () => {
    setIsSubmitting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        toast.error("Usuario no autenticado");
        setIsSubmitting(false);
        return;
      }

      // 1. Change account type to 'live' and reset balance fields
      const passedAt = new Date().toISOString();
      const updateData: Record<string, any> = {
        evaluation_passed: true,
        evaluation_passed_at: passedAt,
        account_type: 'live',
        current_capital: account.initial_capital,
        highest_balance: account.initial_capital,
      };

      if (wantsConsistency) {
        updateData.consistency_min_profit_days = minProfitDays;
        updateData.consistency_withdrawal_pct = withdrawalPct;
      }

      const { error: updateError } = await supabase
        .from('accounts')
        .update(updateData)
        .eq('id', account.id);

      if (updateError) {
        console.error('Error updating account:', updateError);
        toast.error("Error al actualizar la cuenta");
        return;
      }

      // 2. Insert a reset payout to zero out accumulated PnL
      //    Balance = initial + trades_pnl - payouts. To make it = initial,
      //    we insert a payout equal to (currentBalance - initial_capital).
      const accumulatedProfit = currentBalance - account.initial_capital;
      if (accumulatedProfit > 0) {
        const { error: payoutError } = await supabase
          .from('payouts')
          .insert({
            user_id: user.id,
            account_id: account.id,
            amount: accumulatedProfit,
            payout_date: new Date().toISOString(),
            notes: '🔄 Reset automático por aprobación de evaluación',
          });

        if (payoutError) {
          console.error('Error inserting reset payout:', payoutError);
          // Non-critical: account type is already updated
        }
      }

      toast.success("🎉 ¡Felicitaciones! Tu cuenta ahora es fondeada (Live).");
      queryClient.invalidateQueries({ queryKey: ['accounts'] });
      queryClient.invalidateQueries({ queryKey: ['trades'] });
      queryClient.invalidateQueries({ queryKey: ['payouts'] });
      queryClient.invalidateQueries({ queryKey: ['payouts-list'] });
      setShowPassDialog(false);
    } catch (error) {
      console.error('Error:', error);
      toast.error("Error al procesar la aprobación");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card className={`${cardBorderColor} transition-all duration-300 overflow-hidden shadow-sm hover:shadow-md`}>
      {/* ── Header ── */}
      <CardHeader className="pb-2 pt-3 px-4 border-b border-border/50 bg-muted/20">
        <div className="flex justify-between items-center">
          <CardTitle className="text-xs font-medium text-muted-foreground flex items-center gap-1.5 uppercase tracking-wide">
            <TrendingDown className="h-3.5 w-3.5" />
            Riesgo ({drawdownType === 'trailing' ? 'Trailing' : 'Fijo'})
          </CardTitle>
          <div className={`px-2 py-0.5 rounded-full text-[10px] font-semibold flex items-center gap-1 border ${badgeClasses}`}>
            {badgeIcon}
            {badgeText}
          </div>
        </div>
      </CardHeader>

      {/* ── Content ── */}
      <CardContent className="px-4 pt-4 pb-4 space-y-4">

        {/* 🎉 Congratulations Banner */}
        {showCongrats && (
          <div className="rounded-lg border-2 border-emerald-500/50 p-4 bg-gradient-to-r from-emerald-500/10 via-emerald-400/5 to-teal-500/10 animate-in fade-in slide-in-from-top-2 duration-500">
            <div className="flex items-center gap-2 mb-2">
              <PartyPopper className="h-5 w-5 text-emerald-400 animate-bounce" />
              <span className="text-sm font-bold text-emerald-400">🎉 ¡Objetivo Alcanzado!</span>
            </div>
            <p className="text-xs text-muted-foreground mb-3">
              ¡Felicitaciones! Alcanzaste el profit objetivo de {formatCurrency(profitTarget!)}. 
              ¿Aprobaste la prueba de fondeo?
            </p>
            <Button
              size="sm"
              className="w-full bg-emerald-600 hover:bg-emerald-700 gap-2"
              onClick={() => setShowPassDialog(true)}
            >
              <Trophy className="h-4 w-4" />
              ¡Aprobé la cuenta!
            </Button>
          </div>
        )}

        {/* Balance Actual — hero stat */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 text-muted-foreground">
            <DollarSign className="w-3.5 h-3.5" />
            <span className="text-xs font-medium uppercase tracking-wider">Balance</span>
          </div>
          <span className="text-lg font-bold tracking-tight text-foreground">
            {formatCurrency(currentBalance)}
          </span>
        </div>

        {/* Distancia al Límite */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 text-muted-foreground">
            <Ruler className="w-3.5 h-3.5" />
            <span className="text-xs font-medium uppercase tracking-wider">Distancia</span>
          </div>
          <span className={`text-lg font-bold tracking-tight ${distanceTextColor}`}>
            {distanceToLimit > 0 ? '+' : ''}{formatCurrency(distanceToLimit)}
          </span>
        </div>

        {/* Progress bar */}
        <div className="space-y-1">
          <div className="w-full h-2 bg-muted/40 rounded-full overflow-hidden">
            <div
              className={`h-full rounded-full transition-all duration-500 ${progressBarColor}`}
              style={{ width: `${progressPct}%` }}
            />
          </div>
          <div className="flex justify-between text-[10px] text-muted-foreground">
            <span>Límite</span>
            <span>{progressPct.toFixed(0)}% disponible</span>
          </div>
        </div>

        {/* Separator */}
        <div className="border-t border-border/40" />

        {/* Límite de Pérdida */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
            <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Límite</span>
          </div>
          <span className="text-base font-mono font-semibold text-red-400/90">
            {formatCurrency(lossLimit)}
          </span>
        </div>

        {/* Pico Histórico (solo trailing) */}
        {drawdownType === 'trailing' && (
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Trophy className="w-3.5 h-3.5 text-amber-500" />
              <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Pico</span>
            </div>
            <span className="text-base font-mono font-semibold text-amber-500/90">
              {formatCurrency(highWaterMark)}
            </span>
          </div>
        )}

        {/* Capital Inicial (solo fixed) */}
        {drawdownType === 'fixed' && (
          <div className="flex items-center justify-between opacity-60">
            <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Capital Inicial</span>
            <span className="text-base font-mono font-medium text-muted-foreground">
              {formatCurrency(account.initial_capital)}
            </span>
          </div>
        )}

        {/* Objetivo de Profit */}
        {profitAchievement && (() => {
          const { remaining, progressPctTarget, remainingPct, isAchieved, targetBalance } = profitAchievement;
          return (
            <>
              <div className="border-t border-border/40" />
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Target className="w-3.5 h-3.5 text-sky-400" />
                  <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Objetivo</span>
                </div>
                <span className="text-base font-mono font-semibold text-sky-400/90">
                  {formatCurrency(targetBalance)}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-xs text-muted-foreground">Faltan</span>
                <div className="flex items-center gap-2">
                  <span className={`text-sm font-bold ${isAchieved ? 'text-emerald-400' : 'text-sky-300'}`}>
                    {isAchieved ? '✓ Logrado' : `${formatCurrency(remaining)} (${remainingPct.toFixed(1)}%)`}
                  </span>
                </div>
              </div>
              <div className="space-y-1">
                <div className="w-full h-1.5 bg-muted/40 rounded-full overflow-hidden">
                  <div
                    className={`h-full rounded-full transition-all duration-500 ${isAchieved ? 'bg-emerald-500' : 'bg-sky-500'}`}
                    style={{ width: `${progressPctTarget}%` }}
                  />
                </div>
                <div className="flex justify-between text-[10px] text-muted-foreground">
                  <span>{progressPctTarget.toFixed(0)}% completado</span>
                  <span>{formatCurrency(profitTarget!)}</span>
                </div>
              </div>
            </>
          );
        })()}

      </CardContent>

      {/* ── Account Pass Dialog ── */}
      <AlertDialog open={showPassDialog} onOpenChange={setShowPassDialog}>
        <AlertDialogContent className="max-w-md">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2 text-emerald-400">
              <PartyPopper className="h-5 w-5" />
              ¡Felicitaciones! 🎉
            </AlertDialogTitle>
            <AlertDialogDescription asChild>
              <div className="space-y-4 pt-2">
                <p className="text-sm text-muted-foreground">
                  ¡Aprobaste la prueba de fondeo de <span className="font-bold text-foreground">{account.account_name}</span>!
                  El balance se reseteará a {formatCurrency(account.initial_capital)}.
                </p>

                {/* Consistency Rule Toggle */}
                <div className="rounded-lg border border-border/50 p-4 space-y-4 bg-muted/20">
                  <div className="flex items-center justify-between">
                    <div className="space-y-0.5">
                      <Label className="text-sm font-medium">Regla de Consistencia</Label>
                      <p className="text-[11px] text-muted-foreground">
                        ¿Tu empresa de fondeo pide regla de consistencia para retirar?
                      </p>
                    </div>
                    <Switch
                      checked={wantsConsistency}
                      onCheckedChange={setWantsConsistency}
                    />
                  </div>

                  {wantsConsistency && (
                    <div className="space-y-3 pt-2 border-t border-border/30">
                      <div className="space-y-1.5">
                        <Label htmlFor="min-profit-days" className="text-xs">
                          Mínimo de días profit para retirar
                        </Label>
                        <Input
                          id="min-profit-days"
                          type="number"
                          min="1"
                          max="30"
                          value={minProfitDays}
                          onChange={(e) => setMinProfitDays(parseInt(e.target.value) || 1)}
                          className="h-8"
                        />
                        <p className="text-[10px] text-muted-foreground">
                          Ej: 5 = necesitás al menos 5 días con ganancia para poder retirar
                        </p>
                      </div>
                      <div className="space-y-1.5">
                        <Label htmlFor="withdrawal-pct" className="text-xs">
                          % del profit retirable
                        </Label>
                        <Input
                          id="withdrawal-pct"
                          type="number"
                          min="1"
                          max="100"
                          value={withdrawalPct}
                          onChange={(e) => setWithdrawalPct(parseInt(e.target.value) || 1)}
                          className="h-8"
                        />
                        <p className="text-[10px] text-muted-foreground">
                          Ej: 50 = podés retirar hasta el 50% del profit generado
                        </p>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isSubmitting}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleAccountPass}
              disabled={isSubmitting}
              className="bg-emerald-600 hover:bg-emerald-700"
            >
              {isSubmitting ? "Procesando..." : "Confirmar Aprobación"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </Card>
  );
};

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { TradingPlan } from "@/hooks/useTradingPlan";
import { BookOpen, Shield, Target, Clock, TrendingUp, AlertTriangle, Pencil, Plus } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";

interface TradingPlanCardProps {
    plan: TradingPlan | null;
    isLoading: boolean;
    onEdit: () => void;
}

export const TradingPlanCard = ({ plan, isLoading, onEdit }: TradingPlanCardProps) => {
    if (isLoading) {
        return (
            <Card className="border-border bg-card/50 backdrop-blur-sm animate-pulse">
                <CardContent className="p-6">
                    <div className="h-6 bg-muted rounded w-3/4 mb-4" />
                    <div className="space-y-3">
                        <div className="h-4 bg-muted rounded w-full" />
                        <div className="h-4 bg-muted rounded w-2/3" />
                        <div className="h-4 bg-muted rounded w-1/2" />
                    </div>
                </CardContent>
            </Card>
        );
    }

    if (!plan) {
        return (
            <Card className="border-border bg-card/50 backdrop-blur-sm border-dashed">
                <CardContent className="p-6 flex flex-col items-center justify-center min-h-[300px] text-center gap-4">
                    <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center">
                        <BookOpen className="h-8 w-8 text-primary" />
                    </div>
                    <div>
                        <h3 className="text-lg font-semibold text-foreground mb-1">Sin Trading Plan</h3>
                        <p className="text-sm text-muted-foreground">
                            Define tu plan de trading para mejorar tu disciplina y consistencia.
                        </p>
                    </div>
                    <Button onClick={onEdit} className="gap-2">
                        <Plus className="h-4 w-4" />
                        Crear Plan
                    </Button>
                </CardContent>
            </Card>
        );
    }

    const tradingTypeLabels: Record<string, string> = {
        scalping: "Scalping",
        intraday: "Intraday",
        swing: "Swing",
    };

    const activeRules = (plan.psychological_rules || []).filter((r: any) => r.active);
    const mainSetup = (plan.setup_rules || [])[0];

    return (
        <Card className="border-border bg-card/50 backdrop-blur-sm">
            <CardHeader className="pb-3">
                <div className="flex items-center justify-between">
                    <CardTitle className="text-lg flex items-center gap-2">
                        <BookOpen className="h-5 w-5 text-primary" />
                        Trading Plan
                    </CardTitle>
                    <Button variant="ghost" size="icon" onClick={onEdit} className="h-8 w-8">
                        <Pencil className="h-4 w-4" />
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="pt-0 space-y-4">
                <ScrollArea className="max-h-[calc(100vh-250px)]">
                    <div className="space-y-4 pr-3">
                        {/* General Info */}
                        <div className="space-y-2">
                            {plan.market && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Mercado</span>
                                    <span className="font-medium text-foreground">{plan.market}</span>
                                </div>
                            )}
                            {plan.instrument && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Instrumento</span>
                                    <span className="font-medium text-foreground">{plan.instrument}</span>
                                </div>
                            )}
                            {plan.trading_type && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Tipo</span>
                                    <Badge variant="outline" className="text-xs">
                                        {tradingTypeLabels[plan.trading_type] || plan.trading_type}
                                    </Badge>
                                </div>
                            )}
                            {plan.session && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Sesión</span>
                                    <span className="font-medium text-foreground">{plan.session}</span>
                                </div>
                            )}
                            {(plan.allowed_hours_start || plan.allowed_hours_end) && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground flex items-center gap-1">
                                        <Clock className="h-3 w-3" />
                                        Horario
                                    </span>
                                    <span className="font-medium text-foreground">
                                        {plan.allowed_hours_start?.substring(0, 5) || '--:--'} — {plan.allowed_hours_end?.substring(0, 5) || '--:--'}
                                    </span>
                                </div>
                            )}
                        </div>

                        <Separator className="bg-border/50" />

                        {/* Risk Management */}
                        <div className="space-y-2">
                            <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-1.5">
                                <Shield className="h-3.5 w-3.5" />
                                Gestión de Riesgo
                            </h4>
                            {plan.risk_per_trade != null && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Riesgo/trade</span>
                                    <span className="font-semibold text-loss">{plan.risk_per_trade}%</span>
                                </div>
                            )}
                            {plan.max_daily_risk != null && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Riesgo diario máx</span>
                                    <span className="font-semibold text-loss">{plan.max_daily_risk}%</span>
                                </div>
                            )}
                            {plan.max_trades_per_day != null && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Max trades/día</span>
                                    <span className="font-semibold text-foreground">{plan.max_trades_per_day}</span>
                                </div>
                            )}
                            {plan.min_rr != null && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">R:R mínimo</span>
                                    <span className="font-semibold text-profit">1:{plan.min_rr}</span>
                                </div>
                            )}
                            {plan.stop_after_consecutive_losses != null && (
                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-muted-foreground">Stop tras pérdidas</span>
                                    <span className="font-semibold text-foreground">{plan.stop_after_consecutive_losses} consecutivas</span>
                                </div>
                            )}
                        </div>

                        {/* Psychological Rules */}
                        {activeRules.length > 0 && (
                            <>
                                <Separator className="bg-border/50" />
                                <div className="space-y-2">
                                    <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-1.5">
                                        <AlertTriangle className="h-3.5 w-3.5" />
                                        Reglas Psicológicas
                                    </h4>
                                    <div className="space-y-1.5">
                                        {activeRules.map((rule: any, i: number) => (
                                            <div key={i} className="flex items-start gap-2 text-sm">
                                                <span className="text-primary mt-0.5">•</span>
                                                <span className="text-foreground/80">{rule.rule}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </>
                        )}

                        {/* Main Setup */}
                        {mainSetup && (
                            <>
                                <Separator className="bg-border/50" />
                                <div className="space-y-2">
                                    <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-1.5">
                                        <Target className="h-3.5 w-3.5" />
                                        Setup Principal
                                    </h4>
                                    <div className="p-3 rounded-lg bg-primary/5 border border-primary/10">
                                        <p className="font-medium text-sm text-foreground mb-1.5">{mainSetup.name}</p>
                                        {mainSetup.conditions?.length > 0 && (
                                            <div className="space-y-1 max-h-[200px] overflow-y-auto">
                                                {mainSetup.conditions.map((c: string, i: number) => (
                                                    <p key={i} className="text-xs text-muted-foreground flex items-center gap-1.5">
                                                        <TrendingUp className="h-3 w-3 text-primary/60" />
                                                        {c}
                                                    </p>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </>
                        )}

                        {/* Additional Setups */}
                        {(plan.setup_rules || []).length > 1 && (
                            <div className="space-y-1.5">
                                {(plan.setup_rules || []).slice(1).map((setup: any, i: number) => (
                                    <div key={i} className="p-2 rounded bg-muted/30 text-sm">
                                        <span className="font-medium">{setup.name}</span>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Monthly Goals */}
                        {plan.monthly_goals && Object.keys(plan.monthly_goals).length > 0 && (
                            <>
                                <Separator className="bg-border/50" />
                                <div className="space-y-2">
                                    <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                                        🎯 Objetivos Mensuales
                                    </h4>
                                    <div className="space-y-1.5 text-sm">
                                        {plan.monthly_goals.discipline_goal && (
                                            <p className="text-foreground/80">
                                                <span className="text-muted-foreground">Disciplina:</span> {plan.monthly_goals.discipline_goal}
                                            </p>
                                        )}
                                        {plan.monthly_goals.performance_goal && (
                                            <p className="text-foreground/80">
                                                <span className="text-muted-foreground">Rendimiento:</span> {plan.monthly_goals.performance_goal}
                                            </p>
                                        )}
                                        {plan.monthly_goals.consistency_goal && (
                                            <p className="text-foreground/80">
                                                <span className="text-muted-foreground">Consistencia:</span> {plan.monthly_goals.consistency_goal}
                                            </p>
                                        )}
                                    </div>
                                </div>
                            </>
                        )}

                        {/* Edit button at bottom */}
                        <div className="pt-2">
                            <Button onClick={onEdit} variant="outline" className="w-full gap-2">
                                <Pencil className="h-4 w-4" />
                                Editar Plan
                            </Button>
                        </div>
                    </div>
                </ScrollArea>
            </CardContent>
        </Card>
    );
};

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { Plus, Trash2, Save } from "lucide-react";
import { TradingPlan, TradingPlanInput, PsychologicalRule, SetupRule, MonthlyGoals } from "@/hooks/useTradingPlan";

interface TradingPlanEditModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    plan: TradingPlan | null;
    onSave: (data: TradingPlanInput) => Promise<void>;
    isSaving: boolean;
}

export const TradingPlanEditModal = ({ open, onOpenChange, plan, onSave, isSaving }: TradingPlanEditModalProps) => {
    // General
    const [market, setMarket] = useState("");
    const [instrument, setInstrument] = useState("");
    const [tradingType, setTradingType] = useState("");
    const [session, setSession] = useState("");
    const [hoursStart, setHoursStart] = useState("");
    const [hoursEnd, setHoursEnd] = useState("");

    // Risk
    const [riskPerTrade, setRiskPerTrade] = useState("");
    const [maxDailyRisk, setMaxDailyRisk] = useState("");
    const [maxTradesPerDay, setMaxTradesPerDay] = useState("");
    const [minRR, setMinRR] = useState("");
    const [stopAfterLosses, setStopAfterLosses] = useState("");

    // Dynamic
    const [psychRules, setPsychRules] = useState<PsychologicalRule[]>([]);
    const [setupRules, setSetupRules] = useState<SetupRule[]>([]);
    const [monthlyGoals, setMonthlyGoals] = useState<MonthlyGoals>({
        discipline_goal: "",
        performance_goal: "",
        consistency_goal: "",
    });

    // Populate from existing plan
    useEffect(() => {
        if (plan) {
            setMarket(plan.market || "");
            setInstrument(plan.instrument || "");
            setTradingType(plan.trading_type || "");
            setSession(plan.session || "");
            setHoursStart(plan.allowed_hours_start?.substring(0, 5) || "");
            setHoursEnd(plan.allowed_hours_end?.substring(0, 5) || "");
            setRiskPerTrade(plan.risk_per_trade?.toString() || "");
            setMaxDailyRisk(plan.max_daily_risk?.toString() || "");
            setMaxTradesPerDay(plan.max_trades_per_day?.toString() || "");
            setMinRR(plan.min_rr?.toString() || "");
            setStopAfterLosses(plan.stop_after_consecutive_losses?.toString() || "");
            setPsychRules(plan.psychological_rules?.length ? plan.psychological_rules : []);
            setSetupRules(plan.setup_rules?.length ? plan.setup_rules : []);
            setMonthlyGoals(plan.monthly_goals || { discipline_goal: "", performance_goal: "", consistency_goal: "" });
        } else {
            // Defaults for new plan
            setMarket("");
            setInstrument("");
            setTradingType("");
            setSession("");
            setHoursStart("");
            setHoursEnd("");
            setRiskPerTrade("");
            setMaxDailyRisk("");
            setMaxTradesPerDay("");
            setMinRR("");
            setStopAfterLosses("");
            setPsychRules([
                { rule: "No mover Stop Loss", active: true },
                { rule: "No revenge trading", active: true },
            ]);
            setSetupRules([]);
            setMonthlyGoals({ discipline_goal: "", performance_goal: "", consistency_goal: "" });
        }
    }, [plan, open]);

    // Psych rules handlers
    const addPsychRule = () => {
        setPsychRules(prev => [...prev, { rule: "", active: true }]);
    };
    const removePsychRule = (index: number) => {
        setPsychRules(prev => prev.filter((_, i) => i !== index));
    };
    const updatePsychRule = (index: number, field: keyof PsychologicalRule, value: any) => {
        setPsychRules(prev => prev.map((r, i) => i === index ? { ...r, [field]: value } : r));
    };

    // Setup rules handlers
    const addSetupRule = () => {
        setSetupRules(prev => [...prev, { name: "", conditions: [""] }]);
    };
    const removeSetupRule = (index: number) => {
        setSetupRules(prev => prev.filter((_, i) => i !== index));
    };
    const updateSetupName = (index: number, name: string) => {
        setSetupRules(prev => prev.map((s, i) => i === index ? { ...s, name } : s));
    };
    const addCondition = (setupIndex: number) => {
        setSetupRules(prev => prev.map((s, i) => i === setupIndex ? { ...s, conditions: [...s.conditions, ""] } : s));
    };
    const removeCondition = (setupIndex: number, condIndex: number) => {
        setSetupRules(prev => prev.map((s, i) =>
            i === setupIndex ? { ...s, conditions: s.conditions.filter((_, ci) => ci !== condIndex) } : s
        ));
    };
    const updateCondition = (setupIndex: number, condIndex: number, value: string) => {
        setSetupRules(prev => prev.map((s, i) =>
            i === setupIndex ? { ...s, conditions: s.conditions.map((c, ci) => ci === condIndex ? value : c) } : s
        ));
    };

    const handleSave = async () => {
        const data: TradingPlanInput = {
            market: market || null,
            instrument: instrument || null,
            trading_type: tradingType || null,
            session: session || null,
            allowed_hours_start: hoursStart ? hoursStart + ":00" : null,
            allowed_hours_end: hoursEnd ? hoursEnd + ":00" : null,
            risk_per_trade: riskPerTrade ? parseFloat(riskPerTrade) : null,
            max_daily_risk: maxDailyRisk ? parseFloat(maxDailyRisk) : null,
            max_trades_per_day: maxTradesPerDay ? parseInt(maxTradesPerDay) : null,
            min_rr: minRR ? parseFloat(minRR) : null,
            stop_after_consecutive_losses: stopAfterLosses ? parseInt(stopAfterLosses) : null,
            psychological_rules: psychRules.filter(r => r.rule.trim()),
            setup_rules: setupRules.filter(s => s.name.trim()).map(s => ({
                ...s,
                conditions: s.conditions.filter(c => c.trim()),
            })),
            monthly_goals: monthlyGoals,
        };

        await onSave(data);
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto bg-card border-border">
                <DialogHeader>
                    <DialogTitle className="text-xl">
                        {plan ? "Editar Trading Plan" : "Crear Trading Plan"}
                    </DialogTitle>
                    <DialogDescription>
                        Define tu plan de trading para mantener disciplina y consistencia.
                    </DialogDescription>
                </DialogHeader>

                <Tabs defaultValue="general" className="mt-2">
                    <TabsList className="grid grid-cols-5 w-full bg-muted/30">
                        <TabsTrigger value="general" className="text-xs">General</TabsTrigger>
                        <TabsTrigger value="risk" className="text-xs">Riesgo</TabsTrigger>
                        <TabsTrigger value="setups" className="text-xs">Setups</TabsTrigger>
                        <TabsTrigger value="psych" className="text-xs">Psicología</TabsTrigger>
                        <TabsTrigger value="goals" className="text-xs">Objetivos</TabsTrigger>
                    </TabsList>

                    {/* Tab 1: General */}
                    <TabsContent value="general" className="space-y-4 mt-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Mercado</Label>
                                <Input
                                    placeholder="Ej: Futuros, Forex, Crypto"
                                    value={market}
                                    onChange={e => setMarket(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Instrumento</Label>
                                <Input
                                    placeholder="Ej: ES, NQ, EURUSD"
                                    value={instrument}
                                    onChange={e => setInstrument(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Tipo de Trading</Label>
                                <Select value={tradingType} onValueChange={setTradingType}>
                                    <SelectTrigger>
                                        <SelectValue placeholder="Seleccionar..." />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="scalping">Scalping</SelectItem>
                                        <SelectItem value="intraday">Intraday</SelectItem>
                                        <SelectItem value="swing">Swing</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2">
                                <Label>Sesión</Label>
                                <Input
                                    placeholder="Ej: New York, London, Asian"
                                    value={session}
                                    onChange={e => setSession(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Horario Permitido (Inicio)</Label>
                                <Input
                                    type="time"
                                    value={hoursStart}
                                    onChange={e => setHoursStart(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Horario Permitido (Fin)</Label>
                                <Input
                                    type="time"
                                    value={hoursEnd}
                                    onChange={e => setHoursEnd(e.target.value)}
                                />
                            </div>
                        </div>
                    </TabsContent>

                    {/* Tab 2: Risk */}
                    <TabsContent value="risk" className="space-y-4 mt-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label>Riesgo por Trade (%)</Label>
                                <Input
                                    type="number"
                                    step="0.1"
                                    placeholder="Ej: 1"
                                    value={riskPerTrade}
                                    onChange={e => setRiskPerTrade(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Riesgo Diario Máximo (%)</Label>
                                <Input
                                    type="number"
                                    step="0.1"
                                    placeholder="Ej: 3"
                                    value={maxDailyRisk}
                                    onChange={e => setMaxDailyRisk(e.target.value)}
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-3 gap-4">
                            <div className="space-y-2">
                                <Label>Max Trades/Día</Label>
                                <Input
                                    type="number"
                                    placeholder="Ej: 3"
                                    value={maxTradesPerDay}
                                    onChange={e => setMaxTradesPerDay(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>R:R Mínimo</Label>
                                <Input
                                    type="number"
                                    step="0.1"
                                    placeholder="Ej: 2"
                                    value={minRR}
                                    onChange={e => setMinRR(e.target.value)}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Stop tras N pérdidas</Label>
                                <Input
                                    type="number"
                                    placeholder="Ej: 2"
                                    value={stopAfterLosses}
                                    onChange={e => setStopAfterLosses(e.target.value)}
                                />
                            </div>
                        </div>
                    </TabsContent>

                    {/* Tab 3: Setups */}
                    <TabsContent value="setups" className="space-y-4 mt-4">
                        <div className="flex items-center justify-between">
                            <p className="text-sm text-muted-foreground">Agrega tus setups y condiciones de entrada</p>
                            <Button variant="outline" size="sm" onClick={addSetupRule} className="gap-1">
                                <Plus className="h-3 w-3" />
                                Agregar Setup
                            </Button>
                        </div>

                        {setupRules.length === 0 && (
                            <div className="text-center py-8 text-muted-foreground text-sm border border-dashed rounded-lg">
                                No hay setups definidos. Haz clic en "Agregar Setup".
                            </div>
                        )}

                        {setupRules.map((setup, si) => (
                            <div key={si} className="p-4 rounded-lg border border-border bg-muted/10 space-y-3">
                                <div className="flex items-center gap-2">
                                    <Input
                                        value={setup.name}
                                        onChange={e => updateSetupName(si, e.target.value)}
                                        placeholder="Nombre del setup (ej: Breakout Pullback)"
                                        className="font-medium"
                                    />
                                    <Button variant="ghost" size="icon" onClick={() => removeSetupRule(si)} className="text-destructive h-8 w-8 shrink-0">
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>

                                <Separator />

                                <div className="space-y-2">
                                    <Label className="text-xs text-muted-foreground">Condiciones</Label>
                                    {setup.conditions.map((cond, ci) => (
                                        <div key={ci} className="flex items-center gap-2">
                                            <Input
                                                value={cond}
                                                onChange={e => updateCondition(si, ci, e.target.value)}
                                                placeholder={`Condición ${ci + 1}`}
                                                className="text-sm"
                                            />
                                            <Button variant="ghost" size="icon" onClick={() => removeCondition(si, ci)} className="text-muted-foreground h-7 w-7 shrink-0">
                                                <Trash2 className="h-3 w-3" />
                                            </Button>
                                        </div>
                                    ))}
                                    <Button variant="ghost" size="sm" className="text-xs gap-1 text-muted-foreground" onClick={() => addCondition(si)}>
                                        <Plus className="h-3 w-3" />
                                        Agregar condición
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </TabsContent>

                    {/* Tab 4: Psychological Rules */}
                    <TabsContent value="psych" className="space-y-4 mt-4">
                        <div className="flex items-center justify-between">
                            <p className="text-sm text-muted-foreground">Define reglas psicológicas a respetar</p>
                            <Button variant="outline" size="sm" onClick={addPsychRule} className="gap-1">
                                <Plus className="h-3 w-3" />
                                Agregar Regla
                            </Button>
                        </div>

                        {psychRules.length === 0 && (
                            <div className="text-center py-8 text-muted-foreground text-sm border border-dashed rounded-lg">
                                No hay reglas definidas. Haz clic en "Agregar Regla".
                            </div>
                        )}

                        {psychRules.map((rule, i) => (
                            <div key={i} className="flex items-center gap-3 p-3 rounded-lg border border-border bg-muted/10">
                                <Switch
                                    checked={rule.active}
                                    onCheckedChange={checked => updatePsychRule(i, "active", checked)}
                                />
                                <Input
                                    value={rule.rule}
                                    onChange={e => updatePsychRule(i, "rule", e.target.value)}
                                    placeholder="Ej: No mover Stop Loss"
                                    className="flex-1"
                                />
                                <Button variant="ghost" size="icon" onClick={() => removePsychRule(i)} className="text-destructive h-8 w-8 shrink-0">
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        ))}
                    </TabsContent>

                    {/* Tab 5: Goals */}
                    <TabsContent value="goals" className="space-y-4 mt-4">
                        <div className="space-y-2">
                            <Label>Objetivo de Disciplina</Label>
                            <Input
                                placeholder="Ej: 90% trades dentro del plan"
                                value={monthlyGoals.discipline_goal}
                                onChange={e => setMonthlyGoals(prev => ({ ...prev, discipline_goal: e.target.value }))}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Objetivo de Rendimiento</Label>
                            <Input
                                placeholder="Ej: 3% mensual"
                                value={monthlyGoals.performance_goal}
                                onChange={e => setMonthlyGoals(prev => ({ ...prev, performance_goal: e.target.value }))}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Objetivo de Consistencia</Label>
                            <Input
                                placeholder="Ej: No romper reglas psicológicas"
                                value={monthlyGoals.consistency_goal}
                                onChange={e => setMonthlyGoals(prev => ({ ...prev, consistency_goal: e.target.value }))}
                            />
                        </div>
                    </TabsContent>
                </Tabs>

                {/* Save button */}
                <div className="flex justify-end pt-4 border-t border-border mt-4">
                    <Button onClick={handleSave} disabled={isSaving} className="gap-2">
                        <Save className="h-4 w-4" />
                        {isSaving ? "Guardando..." : "Guardar Cambios"}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
};

import { useState } from "react";
import Papa from "papaparse";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Download } from "lucide-react";
import { toast } from "sonner";
import { APP_FIELDS } from "@/utils/csvTransformation";

interface TradeExporterProps {
  buttonVariant?: "default" | "outline" | "ghost";
  className?: string;
}

export function TradeExporter({ buttonVariant = "outline", className }: TradeExporterProps) {
  const [isExporting, setIsExporting] = useState(false);

  const handleExport = async () => {
    setIsExporting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuario no autenticado");

      // Fetch trades
      const { data: tradesData, error: tradesError } = await supabase
        .from('trades')
        .select('*')
        .eq('user_id', user.id)
        .order('entry_time', { ascending: false });

      if (tradesError) throw tradesError;
      if (!tradesData || tradesData.length === 0) {
        toast.info("No hay datos para exportar.");
        setIsExporting(false);
        return;
      }

      // Fetch accounts to map account_name
      const { data: accountsData } = await supabase
        .from('accounts')
        .select('id, account_name')
        .eq('user_id', user.id);

      const accountMap = new Map(accountsData?.map(acc => [acc.id, acc.account_name]) || []);

      // Format data for human consumption based on APP_FIELDS definitions
      const formattedData = tradesData.map(trade => {
        const rowData: Record<string, any> = {};

        // Custom formatting for CSV readability
        APP_FIELDS.forEach(field => {
          let value = trade[field.id as keyof typeof trade];

          if (field.type === 'array' && Array.isArray(value)) {
            value = value.join(', ');
          } else if (field.type === 'boolean') {
            value = value ? 'Yes' : 'No';
          }

          rowData[field.label] = value;
        });

        // Add Account Name
        rowData['Account Name'] = trade.account_id ? (accountMap.get(trade.account_id) || 'N/A') : 'N/A';
        // Add Notes
        rowData['Pre Trade Notes'] = trade.pre_trade_notes || '';
        rowData['Post Trade Notes'] = trade.post_trade_notes || '';

        return rowData;
      });

      // Generate CSV
      const csv = Papa.unparse(formattedData);

      // Trigger Download
      const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement('a');
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);
      link.setAttribute('download', `trades_export_${new Date().toISOString().slice(0, 10)}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      toast.success("Trades exportados correctamente!");
    } catch (error: any) {
      console.error(error);
      toast.error("Error al exportar: " + error.message);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <Button 
      variant={buttonVariant} 
      onClick={handleExport}
      disabled={isExporting}
      className={className}
    >
      <Download className="mr-2 h-4 w-4" />
      {isExporting ? "Exportando..." : "Exportar CSV"}
    </Button>
  );
}

import { useState, useRef, useEffect } from "react";
import Papa from "papaparse";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { toast } from "sonner";
import { APP_FIELDS, transformCSVRow, CSVMapperInfo } from "@/utils/csvTransformation";

interface TradeImporterProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
}

export function TradeImporter({ isOpen, onOpenChange, onSuccess }: TradeImporterProps) {
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [file, setFile] = useState<File | null>(null);
  const [csvHeaders, setCsvHeaders] = useState<string[]>([]);
  const [csvData, setCsvData] = useState<any[]>([]);
  const [mapping, setMapping] = useState<Record<string, string>>({}); // AppField id -> CSVHeader
  const [accounts, setAccounts] = useState<any[]>([]);
  const [selectedAccountId, setSelectedAccountId] = useState<string>("");
  const [isLoading, setIsLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      loadAccounts();
      // Load saved mapping from local storage
      const savedMapping = localStorage.getItem("csv_importer_mapping");
      if (savedMapping) {
        try {
          setMapping(JSON.parse(savedMapping));
        } catch(e) {}
      }
    } else {
      resetState();
    }
  }, [isOpen]);

  const resetState = () => {
    setStep(1);
    setFile(null);
    setCsvHeaders([]);
    setCsvData([]);
    // Do not reset mapping to allow preserving local storage defaults
    setSelectedAccountId("");
    setIsLoading(false);
  };

  const loadAccounts = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase.from('accounts').select('id, account_name').eq('user_id', user.id);
    if (data) setAccounts(data);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFile(file);
    setIsLoading(true);

    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        if (results.meta.fields) {
          setCsvHeaders(results.meta.fields);
          setCsvData(results.data);
          setStep(2);
        } else {
          toast.error("Could not read CSV headers");
        }
        setIsLoading(false);
      },
      error: (error) => {
        toast.error("Error parsing CSV: " + error.message);
        setIsLoading(false);
      }
    });
  };

  const handleMappingChange = (appFieldId: string, csvHeader: string) => {
    setMapping(prev => {
      const newMapping = { ...prev };
      if (csvHeader === "none") {
        delete newMapping[appFieldId];
      } else {
        newMapping[appFieldId] = csvHeader;
      }
      return newMapping;
    });
  };

  const proceedToPreview = () => {
    if (!selectedAccountId) {
      toast.error("Por favor, selecciona una cuenta destino");
      return;
    }

    // Save mapping to localStorage
    localStorage.setItem("csv_importer_mapping", JSON.stringify(mapping));
    setStep(3);
  };

  const handleImport = async () => {
    setIsLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("No autenticado");

      // Transform data
      const config: CSVMapperInfo[] = Object.keys(mapping).map(appField => ({
        appField,
        csvField: mapping[appField],
      }));

      const transformedData = csvData.map(row => 
        transformCSVRow(row, config, user.id, selectedAccountId)
      ).filter(row => row !== null); // maybe add some required field checks

      // Validate required fields explicitly
      const validRows = transformedData.filter(row => row.pnl_neto !== undefined && row.pnl_neto !== null);

      if (validRows.length === 0) {
        throw new Error("Ninguna fila válida para importar (faltan campos obligatorios).");
      }

      // Bulk Insert
      const { error, count } = await supabase
        .from('trades')
        .insert(validRows);

      if (error) {
         console.error("Insert Error", error);
         throw error;
      }

      toast.success(`¡Importación exitosa! ${validRows.length} trades importados.`);
      onSuccess();
      onOpenChange(false);
    } catch (error: any) {
      console.error(error);
      toast.error("Error durante la importación: " + error.message);
    } finally {
      setIsLoading(false);
    }
  };

  // Preview Data: Transform first 3 rows
  const generatePreview = () => {
     const config: CSVMapperInfo[] = Object.keys(mapping).map(appField => ({
        appField,
        csvField: mapping[appField],
      }));
     return csvData.slice(0, 3).map(row => transformCSVRow(row, config, "preview_user", selectedAccountId));
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Importar Operaciones desde CSV</DialogTitle>
          <DialogDescription>
            Sube tu archivo CSV e importa masivamente tus trades.
          </DialogDescription>
        </DialogHeader>

        <div className="py-4">
          {/* STEP 1: UPLOAD */}
          {step === 1 && (
            <div className="flex flex-col items-center justify-center border-2 border-dashed border-border rounded-lg p-12 text-center">
              <div className="mb-4">
                <Label htmlFor="csv-upload" className="mb-2 block text-sm font-medium">Selecciona tu archivo .csv</Label>
                <Input 
                  id="csv-upload" 
                  type="file" 
                  accept=".csv" 
                  className="hidden" 
                  ref={fileInputRef}
                  onChange={handleFileUpload} 
                />
                <Button 
                  onClick={() => fileInputRef.current?.click()} 
                  disabled={isLoading}
                >
                  {isLoading ? "Leyendo..." : "Elegir Archivo"}
                </Button>
              </div>
              <p className="text-xs text-muted-foreground">O arrastra y suelta tu archivo aquí</p>
            </div>
          )}

          {/* STEP 2: MAPPING */}
          {step === 2 && (
            <div className="space-y-6">
               <div className="grid gap-2">
                <Label>Cuenta Destino</Label>
                <Select value={selectedAccountId} onValueChange={setSelectedAccountId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecciona una cuenta..." />
                  </SelectTrigger>
                  <SelectContent>
                    {accounts.map(acc => (
                      <SelectItem key={acc.id} value={acc.id}>{acc.account_name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-4">
                <h4 className="font-medium text-sm">Mapear Columnas (Aplicación {'<-'} CSV)</h4>
                {APP_FIELDS.map(field => (
                  <div key={field.id} className="grid grid-cols-2 gap-4 items-center">
                    <Label className={field.required ? "font-bold" : ""}>
                      {field.label} {field.required && "*"}
                    </Label>
                    <Select 
                      value={mapping[field.id] || "none"} 
                      onValueChange={(val) => handleMappingChange(field.id, val)}
                    >
                      <SelectTrigger>
                         <SelectValue placeholder="Ignorar columna" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="none">-- Ignorar --</SelectItem>
                        {csvHeaders.map(header => (
                          <SelectItem key={header} value={header}>{header}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                ))}
              </div>

              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setStep(1)}>Atrás</Button>
                <Button onClick={proceedToPreview}>Continuar a Vista Previa</Button>
              </div>
            </div>
          )}

          {/* STEP 3: PREVIEW */}
          {step === 3 && (
            <div className="space-y-4">
              <h4 className="font-medium text-sm">Vista Previa (Primeras 3 filas)</h4>
              <div className="overflow-x-auto border rounded-md">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Fecha Entrada</TableHead>
                      <TableHead>Par</TableHead>
                      <TableHead className="text-right">PnL</TableHead>
                      <TableHead>Tipo</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {generatePreview().map((row, idx) => (
                      <TableRow key={idx}>
                         <TableCell>{row.entry_time}</TableCell>
                         <TableCell>{row.par}</TableCell>
                         <TableCell className="text-right">${row.pnl_neto}</TableCell>
                         <TableCell>{row.trade_type}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>

              <div className="bg-muted p-4 rounded-md mt-4">
                 <p className="text-sm">Total de filas a importar: <strong>{csvData.length}</strong></p>
              </div>
            </div>
          )}
        </div>

        {step === 3 && (
          <DialogFooter>
            <Button variant="outline" onClick={() => setStep(2)}>Atrás</Button>
            <Button onClick={handleImport} disabled={isLoading}>
              {isLoading ? "Importando..." : "Confirmar Importación"}
            </Button>
          </DialogFooter>
        )}
      </DialogContent>
    </Dialog>
  );
}

