// ── Hook ───────────────────────────────────────────────────────
export const useMentorIA = () => {
    const queryClient = useQueryClient();
    const [isTyping, setIsTyping] = useState(false);
    const abortRef = useRef<AbortController | null>(null);

    // ── Fetch chat history ──
    const {
        data: messages = [],
        isLoading: isLoadingMessages,
    } = useQuery({
        queryKey: ["mentor-chat"],
        queryFn: async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return [];

            const { data, error } = await (supabase as any)
                .from("mentor_chat_messages")
                .select("*")
                .eq("user_id", user.id)
                .order("created_at", { ascending: true });

            if (error) {
                console.error("Error fetching mentor messages:", error);
                return [];
            }
            return data as ChatMessage[];
        },
    });

    // ── Fetch trades & accounts for metrics ──
    const { data: tradeData } = useQuery({
        queryKey: ["mentor-trades"],
        queryFn: async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return { trades: [] as Trade[], accounts: [] as Account[] };

            const [tradesRes, accountsRes] = await Promise.all([
                supabase.from("trades").select("*").eq("user_id", user.id).order("entry_time", { ascending: true }),
                supabase.from("accounts").select("id, account_name, initial_capital, current_capital").eq("user_id", user.id),
            ]);

            return {
                trades: (tradesRes.data || []) as Trade[],
                accounts: (accountsRes.data || []) as Account[],
            };
        },
    });

    const trades = tradeData?.trades || [];
    const accounts = tradeData?.accounts || [];
    const disciplineScore = calculateDisciplineScore(trades);

    // ── Send message mutation ──
    const sendMutation = useMutation({
        mutationFn: async (userMessage: string) => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) throw new Error("No autenticado");

            // 1. Save user message to DB
            await (supabase as any).from("mentor_chat_messages").insert({
                user_id: user.id,
                role: "user",
                content: userMessage,
            });

            // 2. Build context
            const metricsSummary = buildMetricsSummary(trades, accounts);

            // 3. Build conversation for Gemini API
            const recentMessages = messages.slice(-6).map((m) => ({
                role: m.role,
                content: m.content,
            }));

            const formattedMessages = recentMessages.map((m) => ({
                role: m.role === "assistant" ? "model" : "user",
                parts: [{ text: m.content }],
            }));

            // Add new user message
            formattedMessages.push({
                role: "user",
                parts: [{ text: userMessage }],
            });

            // Prepend system prompt to the conversation history as it's more compatible
            const fullMessages = [
                {
                    role: "user",
                    parts: [{ text: `INSTRUCCIONES DEL SISTEMA:\n${SYSTEM_PROMPT}\n\nCONTEXTO DEL TRADER:\n${metricsSummary}\n\nDiscipline Score: ${disciplineScore}/100` }]
                },
                {
                    role: "model",
                    parts: [{ text: "Entendido. Evaluaré con base en esas instrucciones y el contexto." }]
                },
                ...formattedMessages
            ];

            // 4. Call Gemini API
            const API_KEY = import.meta.env.VITE_GOOGLE_AI_KEY;
            abortRef.current = new AbortController();

            if (!API_KEY) {
                throw new Error("API Key de Google AI no configurada. Verifica tu archivo .env");
            }

            const modelsToTry = [
                "gemini-1.5-flash",
                "gemini-1.5-pro",
                "gemini-1.0-pro"
            ];

            let response;
            let errorDetails = "";

            for (const model of modelsToTry) {
                try {
                    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${API_KEY}`, {
                        method: "POST",
                        headers: {
                            "Content-Type": "application/json",
                        },
                        body: JSON.stringify({
                            contents: fullMessages,
                        }),
                        signal: abortRef.current.signal,
                    });

                    if (res.ok) {
                        response = res;
                        break;
                    } else {
                        const txt = await res.text();
                        console.warn(`Modelo ${model} falló:`, txt);
                        errorDetails += `[${model}: ${res.status}] `;
                    }
                } catch (e: any) {
                    if (e.name === "AbortError") throw e;
                    console.warn(`Error de red con modelo ${model}:`, e);
                }
            }

            if (!response || !response.ok) {
                throw new Error(`Error de la API de IA. Detalles: ${errorDetails}`);
            }

            const data = await response.json();

            if (!data.candidates || data.candidates.length === 0) {
                throw new Error("La IA no devolvió resultados.");
            }

            const assistantContent = data.candidates[0].content.parts[0].text || "Sin respuesta.";

            // 5. Save assistant response to DB
            await (supabase as any).from("mentor_chat_messages").insert({
                user_id: user.id,
                role: "assistant",
                content: assistantContent,
            });

            return assistantContent;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ["mentor-chat"] });
        },
        onError: (err: any) => {
            if (err.name !== "AbortError") {
                toast.error("Error del Mentor IA: " + (err.message || "Desconocido"));
                queryClient.invalidateQueries({ queryKey: ["mentor-chat"] });
            }
        },
    });

    // ── Public API ──
    const sendMessage = useCallback(
        async (message: string) => {
            setIsTyping(true);
            try {
                await sendMutation.mutateAsync(message);
            } finally {
                setIsTyping(false);
            }
        },
        [sendMutation]
    );

    const sendQuickQuestion = useCallback(
        (prompt: string) => {
            sendMessage(prompt);
        },
        [sendMessage]
    );

    const generateWeeklyReport = useCallback(() => {
        sendMessage(
            "Genera un Informe Semanal completo de mi trading. Incluye: 1) Resumen de desempeño, 2) Patrón dominante detectado, 3) Evaluación de disciplina, 4) Plan de mejora concreto para la próxima semana. Sé detallado y directo."
        );
    }, [sendMessage]);

    const clearChat = useCallback(async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        await (supabase as any)
            .from("mentor_chat_messages")
            .delete()
            .eq("user_id", user.id);

        queryClient.invalidateQueries({ queryKey: ["mentor-chat"] });
        toast.success("Historial del Mentor borrado");
    }, [queryClient]);

    return {
        messages,
        isLoadingMessages,
        isTyping,
        sendMessage,
        sendQuickQuestion,
        generateWeeklyReport,
        clearChat,
        disciplineScore,
        trades,
    };
};

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

export interface PsychologicalRule {
    rule: string;
    active: boolean;
}

export interface SetupRule {
    name: string;
    conditions: string[];
}

export interface MonthlyGoals {
    discipline_goal: string;
    performance_goal: string;
    consistency_goal: string;
}

export interface TradingPlan {
    id: string;
    user_id: string;
    market: string | null;
    instrument: string | null;
    trading_type: string | null;
    session: string | null;
    allowed_hours_start: string | null;
    allowed_hours_end: string | null;
    risk_per_trade: number | null;
    max_daily_risk: number | null;
    max_trades_per_day: number | null;
    min_rr: number | null;
    stop_after_consecutive_losses: number | null;
    psychological_rules: PsychologicalRule[];
    setup_rules: SetupRule[];
    monthly_goals: MonthlyGoals | null;
    created_at: string | null;
    updated_at: string | null;
}

export type TradingPlanInput = Omit<TradingPlan, 'id' | 'user_id' | 'created_at' | 'updated_at'>;

export const useTradingPlan = () => {
    const queryClient = useQueryClient();

    const { data: plan, isLoading } = useQuery({
        queryKey: ["trading-plan"],
        queryFn: async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return null;

            const { data, error } = await (supabase as any)
                .from("trading_plans")
                .select("*")
                .eq("user_id", user.id)
                .maybeSingle();

            if (error) {
                console.error("Error fetching trading plan:", error);
                return null;
            }

            return data as TradingPlan | null;
        },
    });

    const saveMutation = useMutation({
        mutationFn: async (planData: TradingPlanInput) => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) throw new Error("No autenticado");

            const payload = {
                ...planData,
                user_id: user.id,
                updated_at: new Date().toISOString(),
            };

            if (plan?.id) {
                // Update existing
                const { data, error } = await (supabase as any)
                    .from("trading_plans")
                    .update(payload)
                    .eq("id", plan.id)
                    .select()
                    .single();

                if (error) throw error;
                return data;
            } else {
                // Insert new
                const { data, error } = await (supabase as any)
                    .from("trading_plans")
                    .insert(payload)
                    .select()
                    .single();

                if (error) throw error;
                return data;
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ["trading-plan"] });
            toast.success("Trading Plan guardado exitosamente");
        },
        onError: (err: any) => {
            toast.error("Error al guardar el plan: " + err.message);
        },
    });

    return {
        plan: plan ?? null,
        isLoading,
        savePlan: saveMutation.mutateAsync,
        isSaving: saveMutation.isPending,
    };
};

