export const ReportBuilder = () => {
  // Estados para la configuración del reporte
  const [startDate, setStartDate] = useState<Date | undefined>(undefined);
  const [endDate, setEndDate] = useState<Date | undefined>(undefined);
  const [selectedColumns, setSelectedColumns] = useState<string[]>(['par', 'pnl_neto', 'entry_time']);
  const [filters, setFilters] = useState<Filter[]>([]);
  const [groupBy, setGroupBy] = useState<string[]>([]);
  const [aggregations, setAggregations] = useState<{ column: string; function: string }[]>([]);
  const [orderByColumn, setOrderByColumn] = useState<string>('');
  const [orderByDirection, setOrderByDirection] = useState<'ASC' | 'DESC'>('DESC');

  // Estados para los resultados
  const [reportData, setReportData] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Función para añadir un filtro
  const addFilter = () => {
    const newFilter: Filter = {
      id: Date.now().toString(),
      column: '',
      operator: '=',
      value: '',
    };
    setFilters([...filters, newFilter]);
  };

  // Función para eliminar un filtro
  const removeFilter = (filterId: string) => {
    setFilters(filters.filter(f => f.id !== filterId));
  };

  // Función para actualizar un filtro
  const updateFilter = (filterId: string, field: keyof Filter, value: string) => {
    setFilters(filters.map(f => 
      f.id === filterId ? { ...f, [field]: value } : f
    ));
  };

  // Función para añadir agregación
  const addAggregation = () => {
    setAggregations([...aggregations, { column: '', function: 'SUM' }]);
  };

  // Función para eliminar agregación
  const removeAggregation = (index: number) => {
    setAggregations(aggregations.filter((_, i) => i !== index));
  };

  // Función para actualizar agregación
  const updateAggregation = (index: number, field: 'column' | 'function', value: string) => {
    setAggregations(aggregations.map((agg, i) => 
      i === index ? { ...agg, [field]: value } : agg
    ));
  };

  // Función para generar el reporte
  const handleGenerateReport = async () => {
    try {
      setIsLoading(true);
      setError(null);

      // Construir la configuración del reporte
      const config: ReportConfig = {
        columns: selectedColumns,
      };

      // Añadir rango de fechas si está definido
      if (startDate && endDate) {
        config.date_range = {
          start: startDate.toISOString(),
          end: endDate.toISOString(),
        };
      }

      // Añadir filtros si existen
      if (filters.length > 0) {
        config.filters = filters.filter(f => f.column && f.value);
      }

      // Añadir agrupación si está definida
      if (groupBy.length > 0) {
        config.group_by = groupBy;
        if (aggregations.length > 0) {
          config.aggregations = aggregations.filter(agg => agg.column);
        }
      }

      // Añadir ordenamiento si está definido
      if (orderByColumn) {
        config.order_by = {
          column: orderByColumn,
          direction: orderByDirection,
        };
      }

      // Llamar a la función RPC
      const { data, error } = await supabase.rpc('create_custom_report', { 
        config: config 
      });

      if (error) {
        throw error;
      }

      setReportData(data || []);
      toast.success(`Reporte generado con ${data?.length || 0} registros`);
    } catch (err: any) {
      console.error('Error generando reporte:', err);
      setError(err.message || 'Error al generar el reporte');
      toast.error('Error al generar el reporte');
    } finally {
      setIsLoading(false);
    }
  };

  // Función para exportar a CSV
  const exportToCSV = () => {
    if (reportData.length === 0) {
      toast.error('No hay datos para exportar');
      return;
    }

    // Obtener las columnas del primer objeto
    const columns = Object.keys(reportData[0]);

    // Crear el header CSV
    const headers = columns.join(',');

    // Crear las filas CSV
    const rows = reportData.map(row => 
      columns.map(col => {
        const value = row[col];
        // Escapar comillas y envolver en comillas si contiene comas
        const stringValue = String(value || '');
        return stringValue.includes(',') ? `"${stringValue.replace(/"/g, '""')}"` : stringValue;
      }).join(',')
    );

    // Combinar header y filas
    const csvContent = [headers, ...rows].join('\n');

    // Crear y descargar el archivo
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `reporte_${format(new Date(), 'yyyy-MM-dd_HH-mm-ss')}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    toast.success('Reporte exportado exitosamente');
  };

  return (
    <div className="container mx-auto px-4 py-8 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold">Constructor de Reportes</h1>
          <p className="text-muted-foreground mt-2">
            Crea reportes personalizados de tus trades con filtros y agrupaciones
          </p>
        </div>
        <div className="flex gap-2">
          <Button onClick={handleGenerateReport} disabled={isLoading} className="gap-2">
            <FileText className="h-4 w-4" />
            {isLoading ? 'Generando...' : 'Generar Reporte'}
          </Button>
          {reportData.length > 0 && (
            <Button onClick={exportToCSV} variant="outline" className="gap-2">
              <Download className="h-4 w-4" />
              Exportar CSV
            </Button>
          )}
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-2">
        {/* Sección de Configuración */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Filter className="h-5 w-5" />
              Configuración del Reporte
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Rango de Fechas */}
            <div className="space-y-4">
              <Label className="text-base font-semibold">Rango de Fechas</Label>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="start-date">Desde</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button variant="outline" className="w-full justify-start text-left font-normal">
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {startDate ? format(startDate, "dd/MM/yyyy") : "Seleccionar fecha"}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0">
                      <Calendar
                        mode="single"
                        selected={startDate}
                        onSelect={setStartDate}
                        initialFocus
                      />
                    </PopoverContent>
                  </Popover>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="end-date">Hasta</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button variant="outline" className="w-full justify-start text-left font-normal">
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {endDate ? format(endDate, "dd/MM/yyyy") : "Seleccionar fecha"}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0">
                      <Calendar
                        mode="single"
                        selected={endDate}
                        onSelect={setEndDate}
                        initialFocus
                      />
                    </PopoverContent>
                  </Popover>
                </div>
              </div>
            </div>

            {/* Columnas a Mostrar */}
            <div className="space-y-4">
              <Label className="text-base font-semibold">Columnas a Mostrar</Label>
              <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto">
                {AVAILABLE_COLUMNS.map((column) => (
                  <div key={column.value} className="flex items-center space-x-2">
                    <Checkbox
                      id={column.value}
                      checked={selectedColumns.includes(column.value)}
                      onCheckedChange={(checked) => {
                        if (checked) {
                          setSelectedColumns([...selectedColumns, column.value]);
                        } else {
                          setSelectedColumns(selectedColumns.filter(col => col !== column.value));
                        }
                      }}
                    />
                    <Label htmlFor={column.value} className="text-sm">
                      {column.label}
                    </Label>
                  </div>
                ))}
              </div>
            </div>

            {/* Filtros */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <Label className="text-base font-semibold">Filtros</Label>
                <Button onClick={addFilter} size="sm" variant="outline" className="gap-2">
                  <Plus className="h-4 w-4" />
                  Añadir Filtro
                </Button>
              </div>
              <div className="space-y-3">
                {filters.map((filter) => (
                  <div key={filter.id} className="flex gap-2 items-end">
                    <div className="flex-1">
                      <Label htmlFor={`filter-column-${filter.id}`}>Columna</Label>
                      <Select
                        value={filter.column}
                        onValueChange={(value) => updateFilter(filter.id, 'column', value)}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Seleccionar columna" />
                        </SelectTrigger>
                        <SelectContent>
                          {AVAILABLE_COLUMNS.map((column) => (
                            <SelectItem key={column.value} value={column.value}>
                              {column.label}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="flex-1">
                      <Label htmlFor={`filter-operator-${filter.id}`}>Operador</Label>
                      <Select
                        value={filter.operator}
                        onValueChange={(value) => updateFilter(filter.id, 'operator', value)}
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Operador" />
                        </SelectTrigger>
                        <SelectContent>
                          {OPERATORS.map((op) => (
                            <SelectItem key={op.value} value={op.value}>
                              {op.label}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="flex-1">
                      <Label htmlFor={`filter-value-${filter.id}`}>Valor</Label>
                      <Input
                        id={`filter-value-${filter.id}`}
                        value={filter.value}
                        onChange={(e) => updateFilter(filter.id, 'value', e.target.value)}
                        placeholder="Valor del filtro"
                      />
                    </div>
                    <Button
                      onClick={() => removeFilter(filter.id)}
                      size="sm"
                      variant="outline"
                      className="text-destructive hover:text-destructive"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                ))}
              </div>
            </div>

            {/* Agrupación */}
            <div className="space-y-4">
              <Label className="text-base font-semibold">Agrupación (Opcional)</Label>
              <div className="space-y-2">
                <Label htmlFor="group-by">Agrupar por</Label>
                <Select
                  value={groupBy[0] || ''}
                  onValueChange={(value) => setGroupBy(value ? [value] : [])}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Seleccionar columna para agrupar" />
                  </SelectTrigger>
                  <SelectContent>
                    {AVAILABLE_COLUMNS.map((column) => (
                      <SelectItem key={column.value} value={column.value}>
                        {column.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {groupBy.length > 0 && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Agregaciones</Label>
                    <Button onClick={addAggregation} size="sm" variant="outline" className="gap-2">
                      <Plus className="h-4 w-4" />
                      Añadir
                    </Button>
                  </div>
                  <div className="space-y-2">
                    {aggregations.map((agg, index) => (
                      <div key={index} className="flex gap-2 items-end">
                        <div className="flex-1">
                          <Label>Columna</Label>
                          <Select
                            value={agg.column}
                            onValueChange={(value) => updateAggregation(index, 'column', value)}
                          >
                            <SelectTrigger>
                              <SelectValue placeholder="Seleccionar columna" />
                            </SelectTrigger>
                            <SelectContent>
                              {AVAILABLE_COLUMNS.map((column) => (
                                <SelectItem key={column.value} value={column.value}>
                                  {column.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                        <div className="flex-1">
                          <Label>Función</Label>
                          <Select
                            value={agg.function}
                            onValueChange={(value) => updateAggregation(index, 'function', value)}
                          >
                            <SelectTrigger>
                              <SelectValue placeholder="Función" />
                            </SelectTrigger>
                            <SelectContent>
                              {AGGREGATION_FUNCTIONS.map((func) => (
                                <SelectItem key={func.value} value={func.value}>
                                  {func.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                        <Button
                          onClick={() => removeAggregation(index)}
                          size="sm"
                          variant="outline"
                          className="text-destructive hover:text-destructive"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Ordenamiento */}
            <div className="space-y-4">
              <Label className="text-base font-semibold">Ordenamiento</Label>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="order-by-column">Columna</Label>
                  <Select value={orderByColumn} onValueChange={setOrderByColumn}>
                    <SelectTrigger>
                      <SelectValue placeholder="Seleccionar columna" />
                    </SelectTrigger>
                    <SelectContent>
                      {AVAILABLE_COLUMNS.map((column) => (
                        <SelectItem key={column.value} value={column.value}>
                          {column.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Dirección</Label>
                  <RadioGroup value={orderByDirection} onValueChange={(value: 'ASC' | 'DESC') => setOrderByDirection(value)}>
                    <div className="flex items-center space-x-2">
                      <RadioGroupItem value="ASC" id="asc" />
                      <Label htmlFor="asc">Ascendente</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                      <RadioGroupItem value="DESC" id="desc" />
                      <Label htmlFor="desc">Descendente</Label>
                    </div>
                  </RadioGroup>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Sección de Resultados */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Resultados del Reporte
            </CardTitle>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <div className="text-center">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
                  <p className="text-muted-foreground">Generando reporte...</p>
                </div>
              </div>
            ) : error ? (
              <div className="text-center py-8">
                <p className="text-destructive mb-4">{error}</p>
                <Button onClick={handleGenerateReport} variant="outline">
                  Reintentar
                </Button>
              </div>
            ) : reportData.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <p>No hay datos para mostrar</p>
                <p className="text-sm">Configura y genera un reporte para ver los resultados</p>
              </div>
            ) : (
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Badge variant="outline" className="gap-2">
                    <FileText className="h-3 w-3" />
                    {reportData.length} registros
                  </Badge>
                </div>

                <div className="overflow-x-auto max-h-96">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        {Object.keys(reportData[0]).map((column) => (
                          <TableHead key={column} className="whitespace-nowrap">
                            {AVAILABLE_COLUMNS.find(col => col.value === column)?.label || column}
                          </TableHead>
                        ))}
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {reportData.map((row, index) => (
                        <TableRow key={index}>
                          {Object.values(row).map((value, cellIndex) => (
                            <TableCell key={cellIndex} className="whitespace-nowrap">
                              {value !== null && value !== undefined ? String(value) : '-'}
                            </TableCell>
                          ))}
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default ReportBuilder;

import { useParams, Link } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Navbar } from '@/components/Navbar';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowLeft, BrainCircuit, TrendingUp, AlertTriangle, Target, Activity } from 'lucide-react';
import { LineChart, Line, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, BarChart, Bar, Cell } from 'recharts';
import { useToast } from "@/components/ui/use-toast";
import { PnLCalendar } from "@/components/PnLCalendar";
import { WinRateDonutChart } from "@/components/charts/WinRateDonutChart";
import { DailyPerformanceStats } from "@/components/DailyPerformanceStats";

interface StrategyStats {
  realized_win_pct: number;
  rules_followed_win_pct: number;
  current_streak: number;
  most_broken_rule: string;
  winning_trades: number;
  losing_trades: number;
  breakeven_trades: number;
}

interface PerformanceData {
  date: string;
  cumulative_pnl: number;
}

interface RadarChartData {
  name: string;
  value: number;
}

interface BrokenRule {
  rule_id: string;
  rule_text: string;
  broken_count: number;
  total_trades_for_strategy: number;
}

interface CalendarHeatmapData {
  date: Date;
  daily_pnl: number;
  rules_followed_pct: number;
  trade_count: number;
}

const StrategyReport = () => {
  const { strategyId } = useParams<{ strategyId: string }>();
  const [strategyName, setStrategyName] = useState('');
  const [stats, setStats] = useState<StrategyStats | null>(null);
  const [performanceData, setPerformanceData] = useState<PerformanceData[]>([]);
  const [radarData, setRadarData] = useState<RadarChartData[]>([]);
  const [brokenRules, setBrokenRules] = useState<BrokenRule[]>([]);
  const [calendarData, setCalendarData] = useState<CalendarHeatmapData[]>([]);
  const [pnlByHourData, setPnlByHourData] = useState<any[]>([]);
  const [rawTrades, setRawTrades] = useState<any[]>([]);
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    const fetchData = async () => {
      if (!strategyId) return;
      setIsLoading(true);

      try {
        // Obtener nombre de la estrategia
        const { data: stratData, error: stratError } = await supabase
          .from('strategies')
          .select('name')
          .eq('id', strategyId)
          .single();

        if (stratError) throw stratError;
        setStrategyName(stratData?.name || 'Estrategia Desconocida');

        // Obtener trades de la estrategia
        const { data: trades, error: tradesError } = await supabase
          .from('trades')
          .select('*')
          .eq('strategy_id', strategyId)
          .order('entry_time', { ascending: true });

        if (tradesError) throw tradesError;

        setRawTrades(trades || []);

        // Calcular estadísticas
        const calculatedStats = calculateStrategyStats(trades || []);
        setStats(calculatedStats);

        // Preparar datos de rendimiento para gráfico de línea
        const perfData = preparePerformanceData(trades || []);
        setPerformanceData(perfData);

        // Preparar datos para radar chart
        const radarChartData = prepareRadarData(trades || []);
        setRadarData(radarChartData);

        // Obtener reglas rotas (ya no depende de trades, usa RPC)
        const brokenRulesData = await fetchBrokenRules([]);
        setBrokenRules(brokenRulesData);

        // Preparar datos para calendario
        const calendarData = prepareCalendarData(trades || []);
        setCalendarData(calendarData);

        // Obtener PnL por hora
        const { data: pnlByHour, error: pnlByHourError } = await supabase
          .rpc('get_pnl_by_hour_for_strategy', { strategy_uuid: strategyId });

        if (pnlByHourError) {
          console.error("Error obteniendo PnL por hora:", pnlByHourError);
        } else {
          setPnlByHourData(pnlByHour || []);
        }

      } catch (error: any) {
        console.error("Error cargando datos del reporte:", error);
        toast({
          title: "Error",
          description: "No se pudieron cargar los datos del reporte",
          variant: "destructive",
        });
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, [strategyId, toast]);

  const calculateStrategyStats = (trades: any[]): StrategyStats => {
    if (trades.length === 0) {
      return {
        realized_win_pct: 0,
        rules_followed_win_pct: 0,
        current_streak: 0,
        most_broken_rule: 'N/A',
        winning_trades: 0,
        losing_trades: 0,
        breakeven_trades: 0
      };
    }

    const totalTrades = trades.length;
    const wins = trades.filter(t => t.pnl_neto > 0).length;
    const losses = trades.filter(t => t.pnl_neto < 0).length;
    const breakeven = trades.filter(t => t.pnl_neto === 0).length;
    const realizedWinPct = (wins / totalTrades) * 100;

    // Reglas seguidas
    const rulesFollowedTrades = trades.filter(t => t.reglas_cumplidas === true);
    const rulesFollowedWins = rulesFollowedTrades.filter(t => t.pnl_neto > 0).length;
    const rulesFollowedWinPct = rulesFollowedTrades.length > 0
      ? (rulesFollowedWins / rulesFollowedTrades.length) * 100
      : 0;

    // Racha actual
    let currentStreak = 0;
    if (trades.length > 0) {
      const lastTrade = trades[trades.length - 1];
      const isLastWin = lastTrade.pnl_neto > 0;

      for (let i = trades.length - 1; i >= 0; i--) {
        const trade = trades[i];
        if ((isLastWin && trade.pnl_neto > 0) || (!isLastWin && trade.pnl_neto < 0)) {
          currentStreak++;
        } else {
          break;
        }
      }
    }

    // Regla más rota
    const brokenRulesMap = new Map<string, number>();
    trades.forEach(trade => {
      if (!trade.reglas_cumplidas && trade.strategy_id) {
        brokenRulesMap.set(trade.strategy_id, (brokenRulesMap.get(trade.strategy_id) || 0) + 1);
      }
    });

    let mostBrokenRule = 'N/A';
    let maxBroken = 0;
    brokenRulesMap.forEach((count, ruleId) => {
      if (count > maxBroken) {
        maxBroken = count;
        mostBrokenRule = ruleId;
      }
    });

    return {
      realized_win_pct: realizedWinPct,
      rules_followed_win_pct: rulesFollowedWinPct,
      current_streak: currentStreak,
      most_broken_rule: mostBrokenRule,
      winning_trades: wins,
      losing_trades: losses,
      breakeven_trades: breakeven
    };
  };

  const preparePerformanceData = (trades: any[]): PerformanceData[] => {
    let cumulativePnl = 0;
    return trades.map((trade) => {
      cumulativePnl += Number(trade.pnl_neto);
      return {
        date: trade.entry_time ? new Date(trade.entry_time).toLocaleDateString() : 'Unknown',
        cumulative_pnl: cumulativePnl
      };
    });
  };

  const prepareRadarData = (trades: any[]): RadarChartData[] => {
    const winCount = trades.filter(t => t.pnl_neto > 0).length;
    const lossCount = trades.filter(t => t.pnl_neto < 0).length;
    const rulesFollowedCount = trades.filter(t => t.reglas_cumplidas === true).length;
    const totalPnl = trades.reduce((sum, t) => sum + Number(t.pnl_neto), 0);
    const avgPnL = trades.length > 0 ? totalPnl / trades.length : 0;

    return [
      { name: 'Win Rate', value: (winCount / trades.length) * 100 },
      { name: 'Win/Loss Ratio', value: lossCount > 0 ? winCount / lossCount : winCount },
      { name: 'Consistency', value: (rulesFollowedCount / trades.length) * 100 },
      { name: 'Avg PnL', value: Math.abs(avgPnL) },
      { name: 'Total Trades', value: trades.length },
    ];
  };

  const fetchBrokenRules = async (trades: any[]): Promise<BrokenRule[]> => {
    if (!strategyId) return [];

    // Usar la RPC get_broken_rules_stats
    const { data: brokenRulesData, error } = await supabase
      .rpc('get_broken_rules_stats', { strategy_uuid: strategyId });

    if (error) {
      console.error("Error obteniendo estadísticas de reglas rotas:", error);
      return [];
    }

    if (!brokenRulesData) return [];

    return brokenRulesData.map((rule: any) => ({
      rule_id: rule.rule_id,
      rule_text: rule.rule_text,
      broken_count: rule.broken_count,
      total_trades_for_strategy: rule.total_trades_for_strategy
    }));
  };

  const prepareCalendarData = (trades: any[]): CalendarHeatmapData[] => {
    const dailyData = new Map<string, { pnl: number; rules_followed: number; total: number }>();

    trades.forEach(trade => {
      const date = trade.entry_time ? new Date(trade.entry_time).toISOString().split('T')[0] : '';
      if (!date) return;

      if (!dailyData.has(date)) {
        dailyData.set(date, { pnl: 0, rules_followed: 0, total: 0 });
      }

      const dayData = dailyData.get(date)!;
      dayData.pnl += Number(trade.pnl_neto);
      dayData.total += 1;
      if (trade.reglas_cumplidas) {
        dayData.rules_followed += 1;
      }
    });

    return Array.from(dailyData.entries()).map(([date, data]) => ({
      date: new Date(date),
      daily_pnl: data.pnl,
      rules_followed_pct: data.total > 0 ? (data.rules_followed / data.total) * 100 : 0,
      trade_count: data.total
    }));
  };

  const handleAiAnalysis = async () => {
    if (!strategyId) return;

    setIsAnalyzing(true);
    try {
      // Por ahora, usar la función de análisis general
      const { data, error } = await supabase.functions.invoke('analisis-ia');

      if (error) throw error;

      setAiAnalysis(JSON.stringify(data, null, 2));

      toast({
        title: "Análisis completado",
        description: "El análisis de IA se ha generado correctamente",
      });
    } catch (error: any) {
      console.error("Error en análisis de IA:", error);
      toast({
        title: "Error",
        description: "No se pudo completar el análisis de IA",
        variant: "destructive",
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background">
        <Navbar />
        <main className="container mx-auto px-4 py-8">
          <div className="space-y-6">
            <Skeleton className="h-8 w-64" />
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              {[1, 2, 3, 4].map(i => (
                <Skeleton key={i} className="h-32 w-full" />
              ))}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <Skeleton className="h-80 w-full" />
              <Skeleton className="h-80 w-full" />
            </div>
          </div>
        </main>
      </div>
    );
  }

  if (!strategyId) {
    return (
      <div className="min-h-screen bg-background">
        <Navbar />
        <main className="container mx-auto px-4 py-8">
          <div className="text-center">
            <h1 className="text-2xl font-bold text-destructive mb-4">Error</h1>
            <p className="text-muted-foreground">ID de estrategia no encontrado.</p>
            <Link to="/" className="inline-flex items-center mt-4 text-primary hover:underline">
              <ArrowLeft className="mr-2 h-4 w-4" /> Volver al Dashboard
            </Link>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <Navbar />
      <main className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-between mb-6">
          <Link to="/" className="inline-flex items-center text-primary hover:underline">
            <ArrowLeft className="mr-2 h-4 w-4" /> Volver al Dashboard
          </Link>
        </div>

        <h1 className="text-3xl font-bold mb-6">Reporte: {strategyName}</h1>

        {/* Métricas Clave - Grid de 4 columnas */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
          <Card className="flex flex-col items-center justify-center p-4">
            <CardHeader className="p-0 pb-2">
              <CardTitle className="text-sm font-medium text-center">Tasa de Acierto</CardTitle>
            </CardHeader>
            <CardContent className="w-full flex flex-col items-center justify-center p-0">
              <WinRateDonutChart
                wins={stats?.winning_trades || 0}
                losses={stats?.losing_trades || 0}
                breakeven={stats?.breakeven_trades || 0}
              />
              <p className="text-xs text-muted-foreground mt-2">Win rate general</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Win Rate (Reglas Cumplidas)</CardTitle>
              <Target className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-blue-600">
                {stats?.rules_followed_win_pct.toFixed(1)}%
              </div>
              <p className="text-xs text-muted-foreground mt-1">Win rate con disciplina</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Racha Actual</CardTitle>
              <Activity className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {stats?.current_streak || 0}
              </div>
              <p className="text-xs text-muted-foreground mt-1">Racha actual</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Regla Más Rota</CardTitle>
              <AlertTriangle className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-xs font-medium truncate">
                {brokenRules[0]?.rule_text || 'N/A'}
              </div>
              <p className="text-xs text-muted-foreground mt-1">{brokenRules[0]?.broken_count || 0} veces</p>
            </CardContent>
          </Card>
        </div>

        {/* Gráficos - 2 columnas */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
          <Card>
            <CardHeader>
              <CardTitle>Rendimiento Acumulado</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={performanceData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="date" angle={-45} textAnchor="end" height={80} />
                  <YAxis />
                  <Tooltip formatter={(value: number) => [`$${value.toFixed(2)}`, 'PnL Acumulado']} />
                  <Line
                    type="monotone"
                    dataKey="cumulative_pnl"
                    stroke="#3b82f6"
                    strokeWidth={2}
                    dot={false}
                  />
                </LineChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Análisis de Rendimiento</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={300}>
                <RadarChart data={radarData}>
                  <PolarGrid />
                  <PolarAngleAxis dataKey="name" tick={{ fontSize: 11 }} />
                  <PolarRadiusAxis angle={90} domain={[0, 'auto']} tick={{ fontSize: 10 }} />
                  <Radar
                    name="Métrica"
                    dataKey="value"
                    stroke="#3b82f6"
                    fill="#3b82f6"
                    fillOpacity={0.6}
                  />
                  <Tooltip />
                </RadarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        </div>

        {/* Gráfico de PnL por Hora */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle>PnL Neto por Hora del Día (UTC)</CardTitle>
          </CardHeader>
          <CardContent className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={pnlByHourData} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--muted))" />
                <XAxis
                  dataKey="hour_of_day"
                  tickFormatter={(hour) => `${hour}:00`}
                  stroke="hsl(var(--muted-foreground))"
                />
                <YAxis stroke="hsl(var(--muted-foreground))" />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'hsl(var(--background))',
                    border: '1px solid hsl(var(--border))'
                  }}
                  labelFormatter={(label) => `Hora ${label}:00`}
                  formatter={(value: any) => [`$${Number(value).toFixed(2)}`, 'PnL Neto']}
                />
                <Bar dataKey="total_pnl" fill="var(--chart-color)">
                  {pnlByHourData.map((entry, index) => (
                    <Cell
                      key={`cell-${index}`}
                      fill={entry.total_pnl >= 0 ? 'var(--profit-color)' : 'var(--loss-color)'}
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Análisis de Reglas */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
          <Card>
            <CardHeader>
              <CardTitle>Análisis de Reglas</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {brokenRules.length > 0 ? (
                brokenRules.map((rule) => {
                  const total = rule.total_trades_for_strategy;
                  const broken = rule.broken_count; // Usar la variable correcta
                  const compliancePct = total > 0 ? ((total - broken) / total) * 100 : 100;

                  return (
                    <div key={rule.rule_id} className="space-y-2 mb-4">
                      <div className="flex justify-between items-center mb-1">
                        <span className="text-sm font-semibold">{rule.rule_text}</span>
                        <span className="text-sm font-semibold">{compliancePct.toFixed(0)}%</span>
                      </div>
                      <Progress value={compliancePct} className="h-2" />
                      <p className="text-sm text-muted-foreground">
                        {broken} rotura(s) de {total} trades {/* Corregido: usar 'broken' */}
                      </p>
                    </div>
                  );
                })
              ) : (
                <p className="text-sm text-muted-foreground">No hay reglas definidas para esta estrategia.</p>
              )}
            </CardContent>
          </Card>

          {/* <Card>
            <CardHeader>
              <CardTitle className="flex items-center">
                <BrainCircuit className="mr-2 h-5 w-5" />
                Análisis con IA
              </CardTitle>
            </CardHeader>
            <CardContent>
              <Button 
                onClick={handleAiAnalysis} 
                className="w-full mb-4"
                disabled={isAnalyzing}
              >
                <BrainCircuit className="mr-2 h-4 w-4"/>
                {isAnalyzing ? 'Analizando...' : 'Analizar ahora'}
              </Button>
              {aiAnalysis && (
                <div className="mt-4 p-4 bg-muted rounded-lg">
                  <pre className="text-xs whitespace-pre-wrap overflow-auto max-h-64">
                    {aiAnalysis}
                  </pre>
                </div>
              )}
              {!aiAnalysis && (
                <p className="text-sm text-muted-foreground">
                  Haz clic en "Analizar ahora" para obtener insights de la IA sobre esta estrategia.
                </p>
              )}
            </CardContent>
          </Card> */}
        </div>

        {/* Mapa de Calor - Full Width */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle>Mapa de Calor - PnL Diario</CardTitle>
          </CardHeader>
          <CardContent>
            <PnLCalendar trades={rawTrades} />
          </CardContent>
        </Card>

        {/* Estadísticas Diarias */}
        <div className="mb-6">
          <DailyPerformanceStats trades={rawTrades} />
        </div>
      </main>
    </div>
  );
};

