import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Navbar } from "@/components/Navbar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { LineChart } from "lucide-react";

const StrategySelectionPage = () => {
  const [strategies, setStrategies] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchStrategies = async () => {
      setIsLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        setIsLoading(false);
        return;
      }
      const { data, error } = await supabase
        .from('strategies')
        .select('id, name')
        .eq('user_id', user.id)
        .order('name');

      if (!error) setStrategies(data || []);
      setIsLoading(false);
    };
    fetchStrategies();
  }, []);

  return (
    <div className="min-h-screen bg-background">
      <Navbar />
      <main className="container mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold mb-6">Selecciona una Estrategia para ver el Reporte</h1>
        {isLoading ? (
          <p className="text-muted-foreground">Cargando estrategias...</p>
        ) : strategies.length === 0 ? (
          <p className="text-muted-foreground">No tienes estrategias creadas. Ve a Configuración &gt; Gestionar Estrategias para añadir una.</p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {strategies.map((strategy) => (
              <Card key={strategy.id} className="hover:shadow-lg transition-shadow">
                <CardHeader>
                  <CardTitle className="text-lg">{strategy.name}</CardTitle>
                </CardHeader>
                <CardContent>
                  <Link to={`/reporte-estrategia/${strategy.id}`} className="w-full">
                    <Button variant="outline" className="w-full">
                      <LineChart className="h-4 w-4 mr-2" />
                      Ver Reporte
                    </Button>
                  </Link>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default StrategySelectionPage;

import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { ArrowLeft, Pencil, CheckCircle, AlertTriangle, XCircle, Ban, Star } from "lucide-react";
import { Navbar } from "@/components/Navbar";
import { toast } from "sonner";
import { Skeleton } from "@/components/ui/skeleton";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { TradeForm } from "@/components/TradeForm";
import { Label } from "@/components/ui/label";

interface Trade {
  id: string;
  account_id: string | null;
  par: string | null;
  pnl_neto: number;
  riesgo: number | null;
  trade_type: "buy" | "sell";
  setup_rating: string | null;
  entry_time: string;
  exit_time: string;
  pre_trade_notes: string | null;
  post_trade_notes: string | null;
  image_url_m1: string | null;
  image_url_m5: string | null;
  image_url_m15: string | null;
  is_outside_plan: boolean;
  setup_compliance: 'full' | 'partial' | 'none' | null;
  is_trade_of_day?: boolean;
  trade_of_day_image?: string | null;
  trade_of_day_notes?: string | null;
  entry_types?: string[] | null;
  accounts?: {
    account_name: string;
  };
}

// Componente auxiliar para mostrar información en tarjetas
const InfoCard = ({ title, value, isProfit = false, isLoss = false }: {
  title: string;
  value: string | number;
  isProfit?: boolean;
  isLoss?: boolean;
}) => (
  <div className="bg-neutral-800 p-4 rounded-lg">
    <h4 className="text-sm text-neutral-400 mb-1">{title}</h4>
    <p className={`text-xl font-bold ${isProfit ? 'text-[var(--profit-color)]' : isLoss ? 'text-[var(--loss-color)]' : 'text-muted-foreground'}`}>
      {value}
    </p>
  </div>
);

// Componente auxiliar para mostrar notas
const NotesBox = ({ title, notes }: { title: string; notes: string | null }) => (
  <div className="bg-neutral-800 p-4 rounded-lg h-full">
    <h4 className="text-md font-semibold text-neutral-300 mb-2">{title}</h4>
    <p className="text-sm text-neutral-100 whitespace-pre-wrap">{notes || 'Sin notas.'}</p>
  </div>
);

// Componente auxiliar para las miniaturas
const ImageThumbnail = ({ src, label, onImageClick }: { src: string, label: string, onImageClick: (src: string) => void }) => (
  <div className="space-y-2">
    <Label className="text-sm font-medium">{label}</Label>
    <button
      onClick={() => onImageClick(src)}
      className="block w-full h-48 rounded-md overflow-hidden border border-neutral-700 hover:opacity-80 transition-opacity bg-neutral-900"
    >
      <img
        src={src}
        alt={`Gráfico ${label}`}
        className="w-full h-full object-cover"
      />
    </button>
  </div>
);

const TradeDetail = () => {
  const params = useParams();
  const id = params.id;
  const [trade, setTrade] = useState<Trade | null>(null);
  const [loading, setLoading] = useState(true);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [selectedImageUrl, setSelectedImageUrl] = useState<string | null>(null);

  const fetchTradeDetails = async () => {
    if (!id) {
      setLoading(false);
      return;
    }

    setLoading(true);
    try {
      // 1. Obtener el trade y los nombres relacionados
      const { data: tradeData, error: tradeError } = await supabase
        .from('trades')
        .select(`
          *, 
          accounts(account_name)
        `)
        .eq('id', id)
        .single();

      if (tradeError) throw tradeError;
      setTrade(tradeData as unknown as Trade);

    } catch (error: any) {
      console.error("Error fetching trade details:", error);
      toast.error("Error al cargar los detalles del trade: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTradeDetails();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen bg-background">
        <Navbar />
        <main className="container mx-auto px-4 py-8">
          <div className="mb-6">
            <Skeleton className="h-10 w-24" />
          </div>
          <Card className="border-border">
            <CardHeader>
              <Skeleton className="h-8 w-48" />
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[1, 2, 3, 4, 5, 6, 7].map(i => (
                  <Skeleton key={i} className="h-24 w-full" />
                ))}
              </div>
            </CardContent>
          </Card>
        </main>
      </div>
    );
  }

  if (!trade) {
    return (
      <div className="min-h-screen bg-background">
        <Navbar />
        <main className="container mx-auto px-4 py-8">
          <div className="text-center py-8 text-muted-foreground">
            No se encontró la operación
          </div>
          <div className="flex justify-center mt-4">
            <Button asChild>
              <Link to="/">Volver al inicio</Link>
            </Button>
          </div>
        </main>
      </div>
    );
  }

  // Calcular RR
  const pnl = parseFloat(trade.pnl_neto?.toString() || "0");
  const risk = parseFloat(trade.riesgo?.toString() || "0");
  let calculatedRR = "N/A";
  if (risk > 0) {
    calculatedRR = `1 : ${(pnl / risk).toFixed(2)}`;
  }

  // Helpers para Setup Compliance
  const getComplianceInfo = (status: string | null) => {
    switch (status) {
      case 'full': return { text: 'Cumple completamente', icon: <CheckCircle className="h-5 w-5 text-green-500" />, color: 'text-green-500' };
      case 'partial': return { text: 'Cumple parcialmente', icon: <AlertTriangle className="h-5 w-5 text-yellow-500" />, color: 'text-yellow-500' };
      case 'none': return { text: 'No cumple', icon: <XCircle className="h-5 w-5 text-red-500" />, color: 'text-red-500' };
      default: return { text: 'No especificado', icon: <AlertTriangle className="h-5 w-5 text-muted-foreground" />, color: 'text-muted-foreground' };
    }
  };

  const complianceInfo = getComplianceInfo(trade.setup_compliance);

  return (
    <div className="min-h-screen bg-background">
      <Navbar />
      <main className="container mx-auto px-4 py-8 max-w-6xl">
        <div className="mb-6 flex justify-between items-center">
          <Button variant="outline" asChild className="gap-2">
            <Link to="/#trades">
              <ArrowLeft className="h-4 w-4" />
              Volver al Historial
            </Link>
          </Button>

          <Button variant="default" className="gap-2" onClick={() => setIsEditDialogOpen(true)}>
            <Pencil className="h-4 w-4" />
            Editar Trade
          </Button>
        </div>

        <Card className="border-border">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>Detalles del Trade</CardTitle>
              <Badge variant="outline" className="text-lg px-3 py-1">
                {trade.par || 'N/A'}
              </Badge>
            </div>
          </CardHeader>
          <CardContent>
            {/* Información de Fechas */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
              <div className="bg-neutral-800 p-4 rounded-lg">
                <h4 className="text-sm text-neutral-400 mb-1">Fecha y Hora de Entrada</h4>
                <p className="text-lg font-semibold">
                  {trade.entry_time
                    ? format(new Date(trade.entry_time), "dd/MM/yyyy HH:mm:ss")
                    : 'N/A'}
                </p>
              </div>
              <div className="bg-neutral-800 p-4 rounded-lg">
                <h4 className="text-sm text-neutral-400 mb-1">Fecha y Hora de Salida</h4>
                <p className="text-lg font-semibold">
                  {trade.exit_time
                    ? format(new Date(trade.exit_time), "dd/MM/yyyy HH:mm:ss")
                    : 'N/A'}
                </p>
              </div>
            </div>

            {/* Sección de Resumen - Grid de 4 columnas */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 my-6">
              <InfoCard
                title="Cuenta"
                value={trade.accounts?.account_name || 'N/A'}
              />
              <InfoCard
                title="PnL Neto"
                value={`$${pnl.toFixed(2)}`}
                isProfit={pnl > 0}
                isLoss={pnl < 0}
              />
              <InfoCard
                title="Riesgo ($)"
                value={`$${risk.toFixed(2)}`}
              />
              <InfoCard
                title="RR (Calculado)"
                value={calculatedRR}
              />
              <InfoCard
                title="Dirección"
                value={trade.trade_type === 'buy' ? 'Compra' : 'Venta'}
              />
              <InfoCard
                title="Calificación Setup"
                value={trade.setup_rating || 'N/A'}
              />
            </div>

            {/* Tipo de Entrada */}
            {trade.entry_types && trade.entry_types.length > 0 && (
              <div className="mt-6">
                <h3 className="text-lg font-semibold mb-3">Tipo de Entrada</h3>
                <div className="flex flex-wrap gap-2">
                  {trade.entry_types.map((type) => {
                    const badgeColors: Record<string, string> = {
                      'IFVG': 'bg-cyan-500/15 border-cyan-500/40 text-cyan-400',
                      'OB': 'bg-violet-500/15 border-violet-500/40 text-violet-400',
                      'NR': 'bg-amber-500/15 border-amber-500/40 text-amber-400',
                      'BOS': 'bg-emerald-500/15 border-emerald-500/40 text-emerald-400',
                      'Sin setup': 'bg-red-600/20 border-red-500/50 text-red-500',
                    };
                    return (
                      <Badge key={type} variant="outline" className={`px-3 py-1 text-sm font-semibold ${badgeColors[type] || 'bg-primary/10 border-primary/30 text-primary'}`}>
                        {type}
                      </Badge>
                    );
                  })}
                </div>
              </div>
            )}

            {/* 🧠 Evaluación del Plan */}
            <div className={`mt-6 p-4 rounded-lg border flex flex-col gap-4 ${!trade.is_outside_plan
              ? 'bg-green-500/10 border-green-500/30'
              : 'bg-red-500/10 border-red-500/30'
              }`}>
              <div className="flex items-center gap-2 mb-2">
                <h3 className="text-lg font-semibold">🧠 Evaluación del Plan</h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Cumplimiento del Setup */}
                <div className="flex items-center gap-3">
                  {complianceInfo.icon}
                  <div>
                    <h4 className="text-sm text-muted-foreground font-medium">Cumplimiento del Setup</h4>
                    <p className={`font-bold ${complianceInfo.color}`}>{complianceInfo.text}</p>
                  </div>
                </div>

                {/* Estado del Plan */}
                <div className="flex items-center gap-3">
                  {!trade.is_outside_plan ? (
                    <CheckCircle className="h-5 w-5 text-green-500" />
                  ) : (
                    <Ban className="h-5 w-5 text-red-500" />
                  )}
                  <div>
                    <h4 className="text-sm text-muted-foreground font-medium">Estado del Plan</h4>
                    {!trade.is_outside_plan ? (
                      <p className="font-bold text-green-500">🟢 Dentro del plan</p>
                    ) : (
                      <div className="flex flex-col">
                        <p className="font-bold text-red-500">🔴 Fuera del plan</p>
                        <p className="text-xs text-red-400 mt-1">
                          Este trade rompió alguna regla de tu plan (RR, riesgo, límite diario o pérdidas consecutivas).
                        </p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* ⭐ Trade del Día */}
            {trade.is_trade_of_day && (
              <div className="mt-6 p-4 rounded-lg border border-yellow-500/40 bg-yellow-500/5">
                <div className="flex items-center gap-2 mb-3">
                  <Star className="h-5 w-5 text-yellow-400 fill-yellow-400" />
                  <h3 className="text-lg font-semibold text-yellow-300">⭐ Trade del Día</h3>
                </div>

                {trade.trade_of_day_image && (
                  <div className="mb-3">
                    <button
                      onClick={() => setSelectedImageUrl(trade.trade_of_day_image!)}
                      className="block w-full max-w-lg h-64 rounded-md overflow-hidden border border-yellow-500/30 hover:opacity-80 transition-opacity bg-neutral-900"
                    >
                      <img
                        src={trade.trade_of_day_image}
                        alt="Trade del Día"
                        className="w-full h-full object-cover"
                      />
                    </button>
                  </div>
                )}

                {trade.trade_of_day_notes && (
                  <div className="bg-neutral-800/50 p-3 rounded-md">
                    <h4 className="text-sm text-yellow-200/70 font-medium mb-1">¿Por qué es el Trade del Día?</h4>
                    <p className="text-sm text-neutral-100 whitespace-pre-wrap">{trade.trade_of_day_notes}</p>
                  </div>
                )}
              </div>
            )}


            {/* Sección de Notas */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
              <NotesBox
                title="Análisis Pre-Trade"
                notes={trade.pre_trade_notes}
              />
              <NotesBox
                title="Reflexión Post-Trade"
                notes={trade.post_trade_notes}
              />
            </div>

            {/* --- Sección de Imágenes (M1, M5, M15) --- */}
            {(trade.image_url_m1 || trade.image_url_m5 || trade.image_url_m15) && (
              <div className="mt-6 col-span-1 md:col-span-2">
                <h3 className="text-lg font-semibold mb-4">Imágenes del Trade</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {/* M1 */}
                  {trade.image_url_m1 && (
                    <ImageThumbnail
                      src={trade.image_url_m1}
                      label="M1"
                      onImageClick={setSelectedImageUrl}
                    />
                  )}
                  {/* M5 */}
                  {trade.image_url_m5 && (
                    <ImageThumbnail
                      src={trade.image_url_m5}
                      label="M5"
                      onImageClick={setSelectedImageUrl}
                    />
                  )}
                  {/* M15 */}
                  {trade.image_url_m15 && (
                    <ImageThumbnail
                      src={trade.image_url_m15}
                      label="M15"
                      onImageClick={setSelectedImageUrl}
                    />
                  )}
                </div>
              </div>
            )}
            {/* --- Fin Sección de Imágenes --- */}
          </CardContent>
        </Card>

        {/* --- Componente Modal (Lightbox) --- */}
        <Dialog open={!!selectedImageUrl} onOpenChange={() => setSelectedImageUrl(null)}>
          <DialogContent className="max-w-5xl h-[90vh] bg-transparent border-0 shadow-none flex items-center justify-center p-0">
            <img
              src={selectedImageUrl || ''}
              alt="Vista detallada del gráfico"
              className="max-w-full max-h-full object-contain"
            />
          </DialogContent>
        </Dialog>

        <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
          <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Editar Operación</DialogTitle>
            </DialogHeader>
            <TradeForm
              tradeToEdit={trade}
              onSaveSuccess={() => {
                setIsEditDialogOpen(false);
                fetchTradeDetails();
                toast.success("Trade actualizado con éxito");
              }}
            />
          </DialogContent>
        </Dialog>
      </main>
    </div>
  );
};

export default TradeDetail;

import { useEffect, useMemo, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Navbar } from "@/components/Navbar";
import { Link } from "react-router-dom";
import { Eye } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";

const TradesPage = () => {
  const [trades, setTrades] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterPar, setFilterPar] = useState("");
  const [filterStartDate, setFilterStartDate] = useState<Date | undefined>();
  const [filterEndDate, setFilterEndDate] = useState<Date | undefined>();

  useEffect(() => {
    const fetchTrades = async () => {
      setLoading(true);
      const { data, error } = await (supabase as any).rpc("get_trades_list");
      if (error) {
        toast.error("Error al cargar trades: " + error.message);
      } else {
        setTrades(data || []);
      }
      setLoading(false);
    };
    fetchTrades();
  }, []);

  const filteredTrades = useMemo(() => {
    return trades.filter((trade) => {
      const tradeDate = trade?.entry_time ? new Date(trade.entry_time) : undefined;
      const matchPar = filterPar
        ? (trade?.par || "").toLowerCase().includes(filterPar.toLowerCase())
        : true;
      const matchStart = filterStartDate && tradeDate ? tradeDate >= filterStartDate : true;
      const matchEnd = filterEndDate && tradeDate ? tradeDate <= filterEndDate : true;
      return matchPar && matchStart && matchEnd;
    });
  }, [trades, filterPar, filterStartDate, filterEndDate]);

  return (
    <div className="min-h-screen bg-background overflow-x-hidden">
      <Navbar />
      <main className="container mx-auto px-2 sm:px-4 py-4 sm:py-8">
        <div className="mb-6">
          <h1 className="text-xl sm:text-2xl font-semibold">Mis Trades</h1>
          <p className="text-sm text-muted-foreground mt-1">Historial de operaciones</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="grid gap-2">
            <Label htmlFor="filterPar">Filtrar por Par</Label>
            <Input
              id="filterPar"
              placeholder="Ej: ES, EURUSD, BTCUSD"
              value={filterPar}
              onChange={(e) => setFilterPar(e.target.value)}
            />
          </div>
          <div className="grid gap-2">
            <Label htmlFor="filterStart">Desde fecha</Label>
            <Input
              id="filterStart"
              type="date"
              value={filterStartDate ? format(filterStartDate, "yyyy-MM-dd") : ""}
              onChange={(e) =>
                setFilterStartDate(e.target.value ? new Date(e.target.value + "T00:00:00") : undefined)
              }
            />
          </div>
          <div className="grid gap-2">
            <Label htmlFor="filterEnd">Hasta fecha</Label>
            <Input
              id="filterEnd"
              type="date"
              value={filterEndDate ? format(filterEndDate, "yyyy-MM-dd") : ""}
              onChange={(e) =>
                setFilterEndDate(e.target.value ? new Date(e.target.value + "T23:59:59") : undefined)
              }
            />
          </div>
        </div>

        <div className="rounded-md border overflow-x-auto">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="whitespace-nowrap">Fecha</TableHead>
                <TableHead>Par</TableHead>
                <TableHead>PnL</TableHead>
                <TableHead className="hidden sm:table-cell">Dirección</TableHead>
                <TableHead className="hidden sm:table-cell">Cuenta</TableHead>
                <TableHead className="hidden md:table-cell">% Reglas</TableHead>
                <TableHead className="text-center">Acciones</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {loading ? (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8 text-muted-foreground">
                    Cargando trades...
                  </TableCell>
                </TableRow>
              ) : filteredTrades.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={7} className="text-center py-8 text-muted-foreground">
                    No hay resultados para los filtros seleccionados.
                  </TableCell>
                </TableRow>
              ) : (
                filteredTrades.map((trade) => {
                  const pnl = Number(trade?.pnl_neto ?? 0);
                  const isBuy = trade?.trade_type === "buy";
                  return (
                    <TableRow key={trade.id}>
                      <TableCell className="whitespace-nowrap text-xs sm:text-sm">
                        {trade?.entry_time ? format(new Date(trade.entry_time), "dd/MM/yy HH:mm") : "-"}
                      </TableCell>
                      <TableCell className="text-xs sm:text-sm">{trade?.par ?? "-"}</TableCell>
                      <TableCell className={`text-xs sm:text-sm ${pnl > 0 ? "text-green-600" : pnl < 0 ? "text-red-600" : "text-muted-foreground"}`}>
                        {pnl.toLocaleString("es-ES", { style: "currency", currency: "USD" })}
                      </TableCell>
                      <TableCell className={`hidden sm:table-cell ${isBuy ? "text-green-600" : "text-red-600"}`}>
                        {isBuy ? "Compra" : "Venta"}
                      </TableCell>
                      <TableCell className="hidden sm:table-cell text-xs">{trade?.account_name ?? "-"}</TableCell>
                      <TableCell className="hidden md:table-cell">
                        {typeof trade?.rules_compliance_pct === "number"
                          ? `${Math.round(trade.rules_compliance_pct)}%`
                          : "-"}
                      </TableCell>
                      <TableCell className="text-center">
                        <Button variant="ghost" size="icon" asChild>
                          <Link to={`/trade/${trade.id}`}>
                            <Eye className="h-4 w-4" />
                          </Link>
                        </Button>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </div>
      </main>
    </div>
  );
};

export default TradesPage;

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Navbar } from "@/components/Navbar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { format } from "date-fns";
import {
    TrendingUp,
    TrendingDown,
    Activity,
    Target,
    ShieldAlert,
    BrainCircuit,
    CheckCircle,
    XCircle,
    Ban,
    AlertTriangle
} from "lucide-react";
import {
    LineChart,
    Line,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    BarChart,
    Bar,
    Cell
} from 'recharts';
import { Progress } from "@/components/ui/progress";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

// --- Interfaces ---
interface Trade {
    id: string;
    pnl_neto: number;
    riesgo: number | null;
    entry_time: string;
    exit_time: string | null;
    is_outside_plan: boolean;
    setup_compliance: 'full' | 'partial' | 'none' | null;
    entry_types?: string[] | null;
}

interface TradingPlan {
    risk_per_trade: number | null;
    max_trades_per_day: number | null;
    min_rr: number | null;
}

interface ReportStats {
    volume: {
        total_trades: number;
        wins: number;
        losses: number;
        breakeven: number;
    };
    discipline: {
        inside_plan_count: number;
        outside_plan_count: number;
        inside_plan_pct: number;
        days_respecting_plan: number;
        days_breaking_plan: number;
    };
    risk: {
        avg_rr: number;
        avg_risk: number;
        risk_breaches: number; // Trades > risk_per_trade
    };
    psychology: {
        full_compliance_count: number;
        partial_compliance_count: number;
        none_compliance_count: number;
        pnl_full: number;
        pnl_partial: number;
        pnl_none: number;
    };
    performance: {
        win_rate: number;
        profit_factor: number;
        max_drawdown: number;
        best_day_pnl: number;
        worst_day_pnl: number;
        total_pnl: number;
        avg_trade_duration_minutes: number;
    };
    consistency: {
        max_streak_inside: number;
        max_streak_outside: number;
    };
}

const StatCard = ({ title, value, subtext, icon: Icon, valueColor }: {
    title: string;
    value: string | number;
    subtext?: string;
    icon?: any;
    valueColor?: string;
}) => (
    <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{title}</CardTitle>
            {Icon && <Icon className="h-4 w-4 text-muted-foreground" />}
        </CardHeader>
        <CardContent>
            <div className={`text-2xl font-bold ${valueColor || ''}`}>{value}</div>
            {subtext && <p className="text-xs text-muted-foreground mt-1">{subtext}</p>}
        </CardContent>
    </Card>
);

const TradingPlanReport = () => {
    const [stats, setStats] = useState<ReportStats | null>(null);
    const [loading, setLoading] = useState(true);
    const [equityCurve, setEquityCurve] = useState<any[]>([]);
    const [allTrades, setAllTrades] = useState<Trade[]>([]);
    const [tradingPlan, setTradingPlan] = useState<TradingPlan | null>(null);
    const [entryTypeFilter, setEntryTypeFilter] = useState<string | null>(null);
    const [availableEntryTypes, setAvailableEntryTypes] = useState<string[]>([]);
    const [payoutChartData, setPayoutChartData] = useState<{ date: string; amount: number }[]>([]);
    const [avgPayout, setAvgPayout] = useState<number>(0);

    useEffect(() => {
        fetchReportData();
    }, []);

    const fetchReportData = async () => {
        setLoading(true);
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            // 1. Fetch Trading Plan
            const { data: plan } = await (supabase as any)
                .from('trading_plans')
                .select('*')
                .eq('user_id', user.id)
                .single();

            setTradingPlan(plan as TradingPlan);

            // 2. Fetch All Trades
            const { data: tradesData, error } = await supabase
                .from('trades')
                .select('id, pnl_neto, riesgo, entry_time, exit_time, is_outside_plan, setup_compliance, entry_types')
                .eq('user_id', user.id)
                .order('entry_time', { ascending: true });

            if (error) throw error;

            const trades = (tradesData || []) as unknown as Trade[];
            setAllTrades(trades);
            const typesSet = new Set<string>();
            trades.forEach(t => (t.entry_types || []).forEach(type => typesSet.add(type)));
            setAvailableEntryTypes(Array.from(typesSet));

            // 3. Fetch Payouts
            const { data: payoutsData } = await supabase
                .from('payouts')
                .select('id, payout_date, amount')
                .eq('user_id', user.id)
                .order('payout_date', { ascending: true });

            const payouts = (payoutsData || []) as { id: string; payout_date: string; amount: number }[];
            const chart = payouts.map(p => ({
                date: p.payout_date ? format(new Date(p.payout_date), 'dd/MM') : '',
                amount: Number(p.amount) || 0
            }));
            setPayoutChartData(chart);
            const avg = payouts.length > 0 ? payouts.reduce((s, p) => s + Number(p.amount || 0), 0) / payouts.length : 0;
            setAvgPayout(avg);

        } catch (err) {
            console.error("Error fetching report data:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        const tradesForStats = entryTypeFilter
            ? allTrades.filter(t => (t.entry_types || []).includes(entryTypeFilter))
            : allTrades;
        if (tradesForStats.length === 0) {
            setStats({
                volume: { total_trades: 0, wins: 0, losses: 0, breakeven: 0 },
                discipline: { inside_plan_count: 0, outside_plan_count: 0, inside_plan_pct: 0, days_respecting_plan: 0, days_breaking_plan: 0 },
                risk: { avg_rr: 0, avg_risk: 0, risk_breaches: 0 },
                psychology: { full_compliance_count: 0, partial_compliance_count: 0, none_compliance_count: 0, pnl_full: 0, pnl_partial: 0, pnl_none: 0 },
                performance: { win_rate: 0, profit_factor: 0, max_drawdown: 0, best_day_pnl: 0, worst_day_pnl: 0, total_pnl: 0, avg_trade_duration_minutes: 0 },
                consistency: { max_streak_inside: 0, max_streak_outside: 0 }
            });
            setEquityCurve([]);
            return;
        }
        const calculatedStats = calculateStats(tradesForStats, tradingPlan);
        setStats(calculatedStats);
        let runningBalance = 0;
        const curve = tradesForStats.map(t => {
            runningBalance += Number(t.pnl_neto);
            return {
                date: t.entry_time ? format(new Date(t.entry_time), 'dd/MM') : '',
                balance: runningBalance
            };
        });
        setEquityCurve(curve);
    }, [allTrades, tradingPlan, entryTypeFilter]);

    const formatDuration = (minutes: number) => {
        const m = Math.round(minutes);
        const h = Math.floor(m / 60);
        const rem = m % 60;
        if (h > 0) return `${h}h ${rem}m`;
        return `${rem}m`;
    };

    const calculateStats = (trades: Trade[], plan: TradingPlan | null): ReportStats => {
        const totalTrades = trades.length;
        if (totalTrades === 0) {
            return {
                volume: { total_trades: 0, wins: 0, losses: 0, breakeven: 0 },
                discipline: { inside_plan_count: 0, outside_plan_count: 0, inside_plan_pct: 0, days_respecting_plan: 0, days_breaking_plan: 0 },
                risk: { avg_rr: 0, avg_risk: 0, risk_breaches: 0 },
                psychology: { full_compliance_count: 0, partial_compliance_count: 0, none_compliance_count: 0, pnl_full: 0, pnl_partial: 0, pnl_none: 0 },
                performance: { win_rate: 0, profit_factor: 0, max_drawdown: 0, best_day_pnl: 0, worst_day_pnl: 0, total_pnl: 0, avg_trade_duration_minutes: 0 },
                consistency: { max_streak_inside: 0, max_streak_outside: 0 }
            };
        }

        // --- Volume ---
        const wins = trades.filter(t => t.pnl_neto > 0).length;
        const losses = trades.filter(t => t.pnl_neto < 0).length;
        const breakeven = trades.filter(t => t.pnl_neto === 0).length;

        // --- Discipline ---
        const insidePlan = trades.filter(t => !t.is_outside_plan);
        const outsidePlan = trades.filter(t => t.is_outside_plan);
        const insidePlanPct = (insidePlan.length / totalTrades) * 100;

        // Days calculation (Group by date)
        const tradesByDay = new Map<string, Trade[]>();
        trades.forEach(t => {
            const date = t.entry_time.split('T')[0];
            if (!tradesByDay.has(date)) tradesByDay.set(date, []);
            tradesByDay.get(date)?.push(t);
        });

        let daysRespecting = 0;
        let daysBreaking = 0;
        tradesByDay.forEach((dayTrades) => {
            // If ANY trade on that day is outside plan, the day is considered "breaking" (strict view)
            // OR mostly respecting? Let's go with: if user made > 0 mistakes, day is tainted.
            const hasMistake = dayTrades.some(t => t.is_outside_plan);
            if (hasMistake) daysBreaking++;
            else daysRespecting++;
        });

        // --- Risk ---
        let totalRR = 0;
        let rrCount = 0;
        let totalRisk = 0;
        let riskCount = 0;
        let riskBreaches = 0;

        trades.forEach(t => {
            const risk = t.riesgo ? Number(t.riesgo) : 0;
            const pnl = Number(t.pnl_neto);

            if (risk > 0) {
                totalRisk += risk;
                riskCount++;
                if (pnl > 0) {
                    totalRR += (pnl / risk);
                    rrCount++;
                }

                if (plan?.risk_per_trade && risk > plan.risk_per_trade) { // Assuming risk_per_trade is amount, need to check if it's % or amt logic. Using simple amt for now if defined.
                    // If plan uses %, we can't easily check without account balance history. 
                    // Skipping complex % logic for now unless we fetch context.
                }
            }
        });

        const avgRR = rrCount > 0 ? totalRR / rrCount : 0;
        const avgRisk = riskCount > 0 ? totalRisk / riskCount : 0;

        // --- Psychology (Setup Compliance) ---
        let full = 0, partial = 0, none = 0;
        let pnlFull = 0, pnlPartial = 0, pnlNone = 0;

        trades.forEach(t => {
            const compliance = t.setup_compliance || 'none';
            const pnl = Number(t.pnl_neto);

            if (compliance === 'full') { full++; pnlFull += pnl; }
            else if (compliance === 'partial') { partial++; pnlPartial += pnl; }
            else { none++; pnlNone += pnl; }
        });

        // --- Performance ---
        const winRate = (wins / totalTrades) * 100;
        const totalProfit = trades.reduce((acc, t) => acc + (t.pnl_neto > 0 ? t.pnl_neto : 0), 0);
        const totalLoss = Math.abs(trades.reduce((acc, t) => acc + (t.pnl_neto < 0 ? t.pnl_neto : 0), 0));
        const profitFactor = totalLoss > 0 ? totalProfit / totalLoss : totalProfit > 0 ? 100 : 0;
        const totalPnL = trades.reduce((acc, t) => acc + Number(t.pnl_neto), 0);

        // DD Calculation
        let peak = -Infinity;
        let maxDrawdown = 0;
        let running = 0;
        trades.forEach(t => {
            running += Number(t.pnl_neto);
            if (running > peak) peak = running;
            const dd = peak - running;
            if (dd > maxDrawdown) maxDrawdown = dd;
        });

        // Best/Worst Day
        let bestDay = -Infinity;
        let worstDay = Infinity;
        tradesByDay.forEach((dayTrades) => {
            const dailyPnL = dayTrades.reduce((acc, t) => acc + Number(t.pnl_neto), 0);
            if (dailyPnL > bestDay) bestDay = dailyPnL;
            if (dailyPnL < worstDay) worstDay = dailyPnL;
        });
        if (bestDay === -Infinity) bestDay = 0;
        if (worstDay === Infinity) worstDay = 0;

        let durationTotal = 0;
        let durationCount = 0;
        trades.forEach(t => {
            if (t.entry_time && t.exit_time) {
                const start = new Date(t.entry_time).getTime();
                const end = new Date(t.exit_time).getTime();
                if (isFinite(start) && isFinite(end) && end > start) {
                    durationTotal += (end - start) / 60000;
                    durationCount++;
                }
            }
        });
        const avgDurationMinutes = durationCount > 0 ? durationTotal / durationCount : 0;


        // --- Consistency (Streaks) ---
        let maxStreakInside = 0;
        let currentStreakInside = 0;
        let maxStreakOutside = 0;
        let currentStreakOutside = 0;

        trades.forEach(t => {
            if (!t.is_outside_plan) {
                currentStreakInside++;
                currentStreakOutside = 0;
                if (currentStreakInside > maxStreakInside) maxStreakInside = currentStreakInside;
            } else {
                currentStreakOutside++;
                currentStreakInside = 0;
                if (currentStreakOutside > maxStreakOutside) maxStreakOutside = currentStreakOutside;
            }
        });

        return {
            volume: { total_trades: totalTrades, wins, losses, breakeven },
            discipline: {
                inside_plan_count: insidePlan.length,
                outside_plan_count: outsidePlan.length,
                inside_plan_pct: insidePlanPct,
                days_breaking_plan: daysBreaking,
                days_respecting_plan: daysRespecting
            },
            risk: { avg_rr: avgRR, avg_risk: avgRisk, risk_breaches: riskBreaches },
            psychology: {
                full_compliance_count: full, partial_compliance_count: partial, none_compliance_count: none,
                pnl_full: pnlFull, pnl_partial: pnlPartial, pnl_none: pnlNone
            },
            performance: {
                win_rate: winRate, profit_factor: profitFactor, max_drawdown: maxDrawdown,
                best_day_pnl: bestDay, worst_day_pnl: worstDay, total_pnl: totalPnL, avg_trade_duration_minutes: avgDurationMinutes
            },
            consistency: { max_streak_inside: maxStreakInside, max_streak_outside: maxStreakOutside }
        };
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-background">
                <Navbar />
                <main className="container mx-auto px-4 py-8">
                    <Skeleton className="h-12 w-48 mb-6" />
                    <div className="grid gap-6">
                        <Skeleton className="h-40 w-full" />
                        <Skeleton className="h-40 w-full" />
                    </div>
                </main>
            </div>
        );
    }

    if (!stats) return null;

    return (
        <div className="min-h-screen bg-background">
            <Navbar />
            <main className="container mx-auto px-4 py-8 max-w-7xl">
                <h1 className="text-3xl font-bold mb-2">Reporte del Plan de Trading</h1>
                <p className="text-muted-foreground mb-8">Análisis detallado de tu ejecución y disciplina.</p>
                <div className="mb-6 flex flex-wrap items-center gap-3">
                    <div className="w-[220px]">
                        <Select value={entryTypeFilter ?? ""} onValueChange={(v) => setEntryTypeFilter(v || null)}>
                            <SelectTrigger>
                                <SelectValue placeholder="Tipo de entrada" />
                            </SelectTrigger>
                            <SelectContent>
                                {availableEntryTypes.map((type) => (
                                    <SelectItem key={type} value={type}>{type}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                    <Button variant="outline" onClick={() => setEntryTypeFilter(null)} disabled={!entryTypeFilter}>
                        Quitar filtro
                    </Button>
                </div>

                {/* 1. Disciplina */}
                <div className="mb-8">
                    <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
                        <ShieldAlert className="h-5 w-5 text-purple-500" />
                        Disciplina y Apego al Plan
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        <StatCard
                            title="Trades Dentro del Plan"
                            value={`${stats.discipline.inside_plan_pct.toFixed(1)}%`}
                            subtext={`${stats.discipline.inside_plan_count} / ${stats.volume.total_trades}`}
                            icon={CheckCircle}
                            valueColor="text-green-500"
                        />
                        <StatCard
                            title="Trades Fuera del Plan"
                            value={stats.discipline.outside_plan_count}
                            subtext={`Racha máxima: ${stats.consistency.max_streak_outside}`}
                            icon={Ban}
                            valueColor="text-red-500"
                        />
                        <StatCard
                            title="Días Respetando Plan"
                            value={stats.discipline.days_respecting_plan}
                            icon={CheckCircle}
                        />
                        <StatCard
                            title="Días Rompiendo Plan"
                            value={stats.discipline.days_breaking_plan}
                            icon={XCircle}
                            valueColor="text-red-500"
                        />
                    </div>
                    {/* Barra de progreso visual */}
                    <div className="mt-4 p-4 bg-secondary/20 rounded-lg">
                        <div className="flex justify-between text-sm mb-2">
                            <span>Disciplina General</span>
                            <span>{stats.discipline.inside_plan_pct.toFixed(1)}%</span>
                        </div>
                        <Progress value={stats.discipline.inside_plan_pct} className="h-2" />
                    </div>
                </div>

                {/* 2. Performance & Riesgo */}
                <div className="mb-8 ">
                    <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
